{
  "name": "Senyuminn Kost Management",
  "description": "A comprehensive property management system for boarding houses (kost) to track complaints, room status, and maintenance workflows with AI-powered assistance.",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum RoomStatus {
  NORMAL = 'Normal',
  COMPLAINT = 'Ada Keluhan',
  REPAIR = 'Dalam Pengerjaan',
  FINISHED = 'Selesai'
}

export enum ComplaintType {
  AIR = 'Air',
  LISTRIK = 'Listrik',
  BANGUNAN = 'Bangunan',
  LAINNYA = 'Lainnya'
}

export enum WorkflowStatus {
  NEW = 'Baru',
  PROCESS = 'Diproses',
  FINISHED = 'Selesai',
  URGENT = 'Sangat Mendesak'
}

export interface Complaint {
  id: string;
  roomId: number;
  date: string;
  type: ComplaintType;
  description: string;
  status: WorkflowStatus;
  technician?: string;
  deadline?: string;
  notes?: string;
  reporter?: string;
}

export interface Room {
  id: number;
  status: RoomStatus;
  lastIssue?: string;
  image?: string;
}

export type ViewType = 'dashboard' | 'input' | 'history' | 'actions' | 'report';

import { RoomStatus, WorkflowStatus, ComplaintType, Room, Complaint } from './types';

export const INITIAL_ROOMS: Room[] = Array.from({ length: 12 }, (_, i) => ({
  id: i + 1,
  status: i === 0 ? RoomStatus.NORMAL : i === 1 ? RoomStatus.COMPLAINT : i === 2 ? RoomStatus.REPAIR : i === 3 ? RoomStatus.FINISHED : RoomStatus.NORMAL,
  lastIssue: i === 1 ? 'AC Tidak Dingin' : i === 2 ? 'Perbaikan Pipa Air' : i === 3 ? 'Selesai Pengecatan' : undefined,
  image: `https://picsum.photos/seed/room${i + 1}/400/225`
}));

export const INITIAL_COMPLAINTS: Complaint[] = [
  {
    id: 'C001',
    roomId: 2,
    date: '12 Okt 2024',
    type: ComplaintType.AIR,
    description: 'AC Tidak Dingin, sudah 2 jam.',
    status: WorkflowStatus.NEW,
    reporter: 'Budi Santoso'
  },
  {
    id: 'C002',
    roomId: 3,
    date: '11 Okt 2024',
    type: ComplaintType.AIR,
    description: 'Pipa wastafel bocor.',
    status: WorkflowStatus.PROCESS,
    technician: 'Bp. Maman',
    deadline: '2023-10-28',
    notes: 'Sparepart sudah dipesan.'
  }
];

export const TECHNICIANS = [
  'Bp. Maman (Listrik/AC)',
  'Bp. Agus (Umum)',
  'Bp. Jono (Ledeng)'
];

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const suggestFix = async (description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Bertindaklah sebagai manajer kost berpengalaman. Berikan saran singkat (maks 20 kata) untuk menangani keluhan berikut: "${description}"`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Gagal mendapatkan saran AI.";
  }
};

export const summarizeStatus = async (complaints: any[]) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Berikan ringkasan eksekutif sangat singkat tentang status kost berdasarkan data keluhan ini: ${JSON.stringify(complaints)}. Gunakan nada yang profesional dan beri rekomendasi prioritas.`,
    });
    return response.text;
  } catch (error) {
    return "Gagal memproses ringkasan.";
  }
};

