import React, { useState, useEffect } from 'react';
import { Room, RoomStatus, Complaint } from '../types';
import { summarizeStatus } from '../services/gemini';

interface DashboardProps {
  rooms: Room[];
  complaints: Complaint[];
}

export const Dashboard: React.FC<DashboardProps> = ({ rooms, complaints }) => {
  const [aiSummary, setAiSummary] = useState<string>("Sedang memuat analisis AI...");

  useEffect(() => {
    const fetchSummary = async () => {
      const summary = await summarizeStatus(complaints);
      setAiSummary(summary || "Tidak ada data cukup.");
    };
    fetchSummary();
  }, [complaints]);

  const stats = [
    { label: 'Total Keluhan', value: 45, change: '+12%', icon: 'summarize', color: 'border-l-primary', iconBg: 'bg-orange-100 text-primary' },
    { label: 'Keluhan Aktif', value: 12, change: '+5%', icon: 'report_problem', color: 'border-l-rose-500', iconBg: 'bg-rose-50 text-rose-500' },
    { label: 'Sedang Dikerjakan', value: 8, change: 'Stable', icon: 'engineering', color: 'border-l-amber-500', iconBg: 'bg-amber-50 text-amber-500' },
    { label: 'Keluhan Selesai', value: 25, change: '+10%', icon: 'check_circle', color: 'border-l-emerald-500', iconBg: 'bg-emerald-50 text-emerald-500' },
  ];

  const getStatusColor = (status: RoomStatus) => {
    switch(status) {
      case RoomStatus.NORMAL: return 'bg-emerald-50 text-emerald-600';
      case RoomStatus.COMPLAINT: return 'bg-rose-50 text-rose-600';
      case RoomStatus.REPAIR: return 'bg-amber-50 text-amber-600';
      case RoomStatus.FINISHED: return 'bg-orange-50 text-primary';
      default: return 'bg-gray-50 text-gray-600';
    }
  };

  const getRoomBorder = (status: RoomStatus) => {
    switch(status) {
      case RoomStatus.NORMAL: return 'border-t-emerald-500';
      case RoomStatus.COMPLAINT: return 'border-t-rose-500';
      case RoomStatus.REPAIR: return 'border-t-amber-500';
      case RoomStatus.FINISHED: return 'border-t-primary';
      default: return 'border-t-gray-500';
    }
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-500">
      {/* AI Assistant Banner */}
      <div className="bg-gradient-to-r from-orange-500 to-orange-400 p-6 rounded-2xl text-white shadow-lg flex items-center gap-6">
        <div className="bg-white/20 p-4 rounded-full">
          <span className="material-symbols-outlined text-3xl">smart_toy</span>
        </div>
        <div>
          <h3 className="font-bold text-lg mb-1">Analisis AI Senyuminn</h3>
          <p className="text-sm text-orange-50 opacity-90">{aiSummary}</p>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => (
          <div key={idx} className={`bg-white dark:bg-gray-800 p-6 rounded-xl border-l-4 ${stat.color} border border-gray-100 dark:border-gray-700 shadow-sm transition-transform hover:-translate-y-1`}>
            <div className="flex justify-between items-start mb-4">
              <div className={`p-2 ${stat.iconBg} rounded-lg`}>
                <span className="material-symbols-outlined">{stat.icon}</span>
              </div>
              <span className="text-xs font-bold">{stat.change}</span>
            </div>
            <p className="text-gray-500 text-sm font-medium mb-1">{stat.label}</p>
            <p className="text-2xl font-bold dark:text-white">{stat.value}</p>
          </div>
        ))}
      </div>

      {/* Room Status Section */}
      <div>
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-xl font-bold dark:text-white">Status Kamar (1-12)</h3>
          <div className="flex gap-2 flex-wrap">
            {[RoomStatus.NORMAL, RoomStatus.COMPLAINT, RoomStatus.REPAIR, RoomStatus.FINISHED].map((st) => (
              <div key={st} className="flex items-center gap-1.5 px-3 py-1 bg-white dark:bg-gray-800 border border-gray-100 dark:border-gray-700 rounded-full text-[10px] font-semibold">
                <span className={`w-2 h-2 rounded-full ${
                  st === RoomStatus.NORMAL ? 'bg-emerald-500' : 
                  st === RoomStatus.COMPLAINT ? 'bg-rose-500' :
                  st === RoomStatus.REPAIR ? 'bg-amber-500' : 'bg-primary'
                }`}></span> {st}
              </div>
            ))}
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {rooms.map((room) => (
            <div key={room.id} className={`bg-white dark:bg-gray-800 rounded-xl border border-gray-100 dark:border-gray-700 shadow-sm overflow-hidden border-t-4 ${getRoomBorder(room.status)} group`}>
              <div className="p-5">
                <div className="flex justify-between items-start mb-3">
                  <h4 className="text-lg font-bold dark:text-white">Kamar {room.id}</h4>
                  <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${getStatusColor(room.status)}`}>{room.status}</span>
                </div>
                {room.image ? (
                  <div className="aspect-video w-full bg-gray-100 dark:bg-gray-700 rounded-lg mb-4 overflow-hidden relative">
                    <img src={room.image} alt={`Room ${room.id}`} className="w-full h-full object-cover transition-transform group-hover:scale-105" />
                  </div>
                ) : (
                  <div className="aspect-video w-full bg-orange-50 dark:bg-orange-900/10 flex items-center justify-center rounded-lg mb-4">
                    <span className="material-symbols-outlined text-primary/30 text-4xl">home</span>
                  </div>
                )}
                <p className="text-gray-500 text-xs mb-4 min-h-[2.5rem]">
                  {room.lastIssue || 'Siap Huni - Kondisi Baik'}
                </p>
                <button className="w-full py-2 bg-gray-50 dark:bg-gray-700 hover:bg-orange-50 dark:hover:bg-gray-600 hover:text-primary transition-colors text-xs font-bold rounded-lg border border-transparent hover:border-primary/20">
                  Detail Kamar
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ViewType, Room, Complaint } from './types';
import { INITIAL_ROOMS, INITIAL_COMPLAINTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './views/Dashboard';
import { InputComplaint } from './views/InputComplaint';
import { ComplaintActions } from './views/ComplaintActions';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [rooms] = useState<Room[]>(INITIAL_ROOMS);
  const [complaints] = useState<Complaint[]>(INITIAL_COMPLAINTS);

  const getTitle = () => {
    switch(currentView) {
      case 'dashboard': return 'Dashboard Monitoring';
      case 'input': return 'Input Keluhan Baru';
      case 'history': return 'Riwayat Keluhan';
      case 'actions': return 'Manajemen Tindakan Keluhan';
      case 'report': return 'Laporan Bulanan';
      default: return 'Senyuminn Kost';
    }
  };

  const renderView = () => {
    switch(currentView) {
      case 'dashboard':
        return <Dashboard rooms={rooms} complaints={complaints} />;
      case 'input':
        return <InputComplaint />;
      case 'actions':
        return <ComplaintActions complaints={complaints} />;
      case 'history':
        return <div className="p-10 text-center text-gray-400">Tampilan Riwayat Sedang Dikembangkan</div>;
      case 'report':
        return <div className="p-10 text-center text-gray-400">Tampilan Laporan Sedang Dikembangkan</div>;
      default:
        return <Dashboard rooms={rooms} complaints={complaints} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-gray-900">
      <Sidebar currentView={currentView} setView={setView} />
      <main className="flex-1 ml-72 min-h-screen transition-all">
        <Header title={getTitle()} />
        <div className="mx-auto max-w-7xl">
          {renderView()}
        </div>
      </main>

      {/* Dark Mode Toggle Float */}
      <button 
        onClick={() => document.documentElement.classList.toggle('dark')}
        className="fixed bottom-6 right-6 z-50 p-4 bg-white dark:bg-gray-800 rounded-full shadow-2xl border border-gray-100 dark:border-gray-700 flex items-center justify-center hover:scale-110 transition-transform active:scale-95 group"
      >
        <span className="material-symbols-outlined text-primary group-hover:rotate-12 transition-transform">dark_mode</span>
      </button>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

