import React, { useState } from 'react';
import { ViewType, Room, Complaint, RoomStatus } from './types';
import { INITIAL_ROOMS, INITIAL_COMPLAINTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './views/Dashboard';
import { InputComplaint } from './views/InputComplaint';
import { ComplaintActions } from './views/ComplaintActions';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [rooms, setRooms] = useState<Room[]>(INITIAL_ROOMS);
  const [complaints, setComplaints] = useState<Complaint[]>(INITIAL_COMPLAINTS);

  const getTitle = () => {
    switch(currentView) {
      case 'dashboard': return 'Dashboard Monitoring';
      case 'input': return 'Input Keluhan Baru';
      case 'history': return 'Riwayat Keluhan';
      case 'actions': return 'Manajemen Tindakan Keluhan';
      case 'report': return 'Laporan Bulanan';
      default: return 'Senyuminn Kost';
    }
  };

  const handleAddComplaint = (newComplaint: Complaint) => {
    // Tambah keluhan ke list
    setComplaints(prev => [newComplaint, ...prev]);

    // Update status kamar terkait menjadi 'Ada Keluhan'
    setRooms(prevRooms => prevRooms.map(room => 
      room.id === newComplaint.roomId 
        ? { ...room, status: RoomStatus.COMPLAINT, lastIssue: newComplaint.description }
        : room
    ));

    // Pindah ke dashboard setelah input
    setView('dashboard');
  };

  const renderView = () => {
    switch(currentView) {
      case 'dashboard':
        return <Dashboard rooms={rooms} complaints={complaints} />;
      case 'input':
        return <InputComplaint onSave={handleAddComplaint} />;
      case 'actions':
        return <ComplaintActions complaints={complaints} />;
      case 'history':
        return (
          <div className="p-10 space-y-4">
            <h2 className="text-xl font-bold">Riwayat Keluhan</h2>
            {complaints.length === 0 ? (
              <p className="text-gray-400">Belum ada riwayat keluhan.</p>
            ) : (
              <div className="grid gap-4">
                {complaints.map(c => (
                  <div key={c.id} className="p-4 bg-white dark:bg-gray-800 rounded-lg border border-gray-100 dark:border-gray-700">
                    <p className="font-bold">Kamar {c.roomId} - {c.type}</p>
                    <p className="text-sm text-gray-500">{c.description}</p>
                    <p className="text-xs text-primary mt-2">{c.date}</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      case 'report':
        return <div className="p-10 text-center text-gray-400">Tampilan Laporan Sedang Dikembangkan</div>;
      default:
        return <Dashboard rooms={rooms} complaints={complaints} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-gray-900">
      <Sidebar currentView={currentView} setView={setView} />
      <main className="flex-1 ml-72 min-h-screen transition-all">
        <Header title={getTitle()} />
        <div className="mx-auto max-w-7xl">
          {renderView()}
        </div>
      </main>

      {/* Dark Mode Toggle Float */}
      <button 
        onClick={() => document.documentElement.classList.toggle('dark')}
        className="fixed bottom-6 right-6 z-50 p-4 bg-white dark:bg-gray-800 rounded-full shadow-2xl border border-gray-100 dark:border-gray-700 flex items-center justify-center hover:scale-110 transition-transform active:scale-95 group"
      >
        <span className="material-symbols-outlined text-primary group-hover:rotate-12 transition-transform">dark_mode</span>
      </button>
    </div>
  );
};

