import React, { useState, useRef } from 'react';
import { ComplaintType, Complaint, WorkflowStatus } from '../types';
import { suggestFix } from '../services/gemini';

interface InputComplaintProps {
  onSave: (complaint: Complaint) => void;
}

export const InputComplaint: React.FC<InputComplaintProps> = ({ onSave }) => {
  const [description, setDescription] = useState('');
  const [roomId, setRoomId] = useState('');
  const [type, setType] = useState<ComplaintType | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [image, setImage] = useState<string | null>(null);
  const [aiTip, setAiTip] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSuggest = async () => {
    if (!description.trim()) return;
    setIsAiLoading(true);
    const suggestion = await suggestFix(description);
    setAiTip(suggestion || '');
    setIsAiLoading(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = () => {
    if (!roomId || !type || !description) {
      alert('Mohon lengkapi Nomor Kamar, Jenis, dan Deskripsi Keluhan.');
      return;
    }

    const formattedDate = new Date(date).toLocaleDateString('id-ID', { 
      day: '2-digit', 
      month: 'short', 
      year: 'numeric' 
    });

    const newComplaint: Complaint = {
      id: `C${Date.now()}`,
      roomId: parseInt(roomId),
      type: type as ComplaintType,
      description: description,
      date: formattedDate,
      status: WorkflowStatus.NEW,
      reporter: 'Admin Senyuminn',
      image: image || undefined
    };

    onSave(newComplaint);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="mb-8">
        <h1 className="text-3xl font-extrabold text-gray-900 dark:text-white flex items-center gap-3">
