import React, { useState, useEffect } from 'react';
import { Complaint, WorkflowStatus, ComplaintType } from '../types';
import { summarizeStatus } from '../services/gemini';

interface ReportProps {
  complaints: Complaint[];
}

export const Report: React.FC<ReportProps> = ({ complaints }) => {
  const [aiAnalysis, setAiAnalysis] = useState("Sedang menyusun laporan strategis...");

  useEffect(() => {
    const fetchAnalysis = async () => {
      if (complaints.length === 0) {
        setAiAnalysis("Belum ada data untuk dianalisis.");
        return;
      }
      const summary = await summarizeStatus(complaints);
      setAiAnalysis(summary || "Gagal memproses data.");
    };
    fetchAnalysis();
  }, [complaints]);

  const solved = complaints.filter(c => c.status === WorkflowStatus.FINISHED).length;
  const pending = complaints.length - solved;
  const solveRate = complaints.length > 0 ? Math.round((solved / complaints.length) * 100) : 0;

  // Group by type for chart
  const typeStats = Object.values(ComplaintType).map(type => ({
    type,
    count: complaints.filter(c => c.type === type).length
  }));

  const maxCount = Math.max(...typeStats.map(s => s.count), 1);

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-700">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-3xl font-extrabold text-gray-900 dark:text-white">Laporan Pemeliharaan</h1>
          <p className="text-gray-500">Ringkasan performa dan statistik aset Senyuminn Kost.</p>
        </div>
        <button 
          onClick={() => window.print()}
          className="flex items-center gap-2 bg-gray-900 dark:bg-white dark:text-gray-900 text-white px-5 py-2.5 rounded-xl font-bold text-sm hover:opacity-90 transition-opacity"
        >
          <span className="material-symbols-outlined text-lg">print</span>
          Cetak Laporan
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Progress Card */}
        <div className="bg-white dark:bg-gray-800 p-8 rounded-3xl border border-gray-100 dark:border-gray-700 shadow-sm flex flex-col items-center justify-center text-center">
          <div className="relative size-32 mb-4">
            <svg className="size-full" viewBox="0 0 36 36">
              <path className="text-gray-100 dark:text-gray-700 stroke-current" strokeWidth="3" fill="none" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" />
              <path className="text-primary stroke-current" strokeWidth="3" strokeDasharray={`${solveRate}, 100`} strokeLinecap="round" fill="none" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" />
            </svg>
            <div className="absolute inset-0 flex items-center justify-center flex-col">
              <span className="text-2xl font-black dark:text-white">{solveRate}%</span>
              <span className="text-[10px] text-gray-400 font-bold uppercase">Selesai</span>
            </div>
          </div>
          <h3 className="font-bold text-gray-900 dark:text-white">Tingkat Penyelesaian</h3>
          <p className="text-xs text-gray-500 mt-1">{solved} dari {complaints.length} laporan tertangani</p>
        </div>

        {/* AI Executive Summary */}
        <div className="lg:col-span-2 bg-primary/5 border border-primary/10 p-8 rounded-3xl relative overflow-hidden">
          <div className="absolute top-0 right-0 p-4 opacity-10">
            <span className="material-symbols-outlined text-8xl text-primary">auto_awesome</span>
          </div>
          <div className="relative z-10">
            <div className="flex items-center gap-2 mb-4">
              <span className="material-symbols-outlined text-primary">smart_toy</span>
              <h3 className="font-bold text-primary-dark dark:text-primary">Analisis Strategis AI</h3>
            </div>
            <p className="text-gray-700 dark:text-gray-300 leading-relaxed italic">
              "{aiAnalysis}"
            </p>
          </div>
        </div>
      </div>

      {/* Breakdown by Type */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white dark:bg-gray-800 p-8 rounded-3xl border border-gray-100 dark:border-gray-700 shadow-sm">
          <h3 className="font-bold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
            <span className="material-symbols-outlined text-primary">bar_chart</span>
            Distribusi Keluhan
          </h3>
          <div className="space-y-6">
            {typeStats.map(stat => (
              <div key={stat.type} className="space-y-2">
                <div className="flex justify-between text-xs font-bold uppercase tracking-wider text-gray-500">
                  <span>{stat.type}</span>
                  <span>{stat.count} Kasus</span>
                </div>
                <div className="h-2.5 w-full bg-gray-50 dark:bg-gray-900 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-primary transition-all duration-1000" 
                    style={{ width: `${(stat.count / maxCount) * 100}%` }}
                  />
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-white dark:bg-gray-800 p-8 rounded-3xl border border-gray-100 dark:border-gray-700 shadow-sm">
          <h3 className="font-bold text-gray-900 dark:text-white mb-6 flex items-center gap-2">
