                <div className={`size-10 rounded-lg flex items-center justify-center ${
                  c.status === WorkflowStatus.FINISHED ? 'bg-emerald-100 text-emerald-600' : 'bg-orange-100 text-primary'
                }`}>
                  <span className="material-symbols-outlined text-xl">
                    {c.status === WorkflowStatus.FINISHED ? 'check' : 'pending'}
                  </span>
                </div>
                <div>
                  <p className="text-sm font-bold dark:text-white">Kamar {c.roomId} - {c.type}</p>
                  <p className="text-[10px] text-gray-500">{c.date} • {c.status}</p>
                </div>
              </div>
            ))}
            {complaints.length === 0 && <p className="text-gray-400 text-sm italic">Belum ada aktivitas.</p>}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ViewType, Room, Complaint, RoomStatus, WorkflowStatus } from './types';
import { INITIAL_ROOMS, INITIAL_COMPLAINTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './views/Dashboard';
import { InputComplaint } from './views/InputComplaint';
import { ComplaintActions } from './views/ComplaintActions';
import { Report } from './views/Report';
import { Modal } from './components/Modal';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [rooms, setRooms] = useState<Room[]>(INITIAL_ROOMS);
  const [complaints, setComplaints] = useState<Complaint[]>(INITIAL_COMPLAINTS);

  // Modal State
  const [selectedComplaint, setSelectedComplaint] = useState<Complaint | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const getTitle = () => {
    switch(currentView) {
      case 'dashboard': return 'Dashboard Monitoring';
      case 'input': return 'Input Keluhan Baru';
      case 'history': return 'Riwayat Keluhan';
      case 'actions': return 'Manajemen Tindakan';
      case 'report': return 'Laporan Pemeliharaan';
      default: return 'Senyuminn Kost';
    }
  };

  const handleAddComplaint = (newComplaint: Complaint) => {
    setComplaints(prev => [newComplaint, ...prev]);
    setRooms(prevRooms => prevRooms.map(room => 
      room.id === newComplaint.roomId 
        ? { ...room, status: RoomStatus.COMPLAINT, lastIssue: newComplaint.description }
        : room
    ));
    setView('dashboard');
  };

  const handleUpdateStatus = (id: string, nextStatus: WorkflowStatus) => {
    setComplaints(prev => prev.map(c => {
      if (c.id === id) {
        const updated = { ...c, status: nextStatus };

        // Update room status if finished
        if (nextStatus === WorkflowStatus.FINISHED) {
          setRooms(prevRooms => prevRooms.map(room => 
            room.id === c.roomId ? { ...room, status: RoomStatus.NORMAL, lastIssue: undefined } : room
          ));
        } else if (nextStatus === WorkflowStatus.PROCESS) {
          setRooms(prevRooms => prevRooms.map(room => 
            room.id === c.roomId ? { ...room, status: RoomStatus.REPAIR } : room
          ));
        }

        return updated;
      }
      return c;
    }));
  };

  const openDetail = (complaint: Complaint) => {
    setSelectedComplaint(complaint);
    setIsModalOpen(true);
  };

  const renderView = () => {
    switch(currentView) {
      case 'dashboard':
        return <Dashboard rooms={rooms} complaints={complaints} />;
      case 'input':
        return <InputComplaint onSave={handleAddComplaint} />;
      case 'actions':
        return <ComplaintActions complaints={complaints} onUpdateStatus={handleUpdateStatus} onViewDetail={openDetail} />;
      case 'report':
        return <Report complaints={complaints} />;
      case 'history':
        return (
          <div className="p-10 space-y-6 animate-in fade-in duration-500">
            <h2 className="text-2xl font-bold dark:text-white">Riwayat Keluhan Selesai</h2>
            <div className="grid gap-4">
              {complaints.filter(c => c.status === WorkflowStatus.FINISHED).length === 0 ? (
                <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-2xl border border-dashed border-gray-200">
                   <p className="text-gray-400">Belum ada riwayat keluhan yang selesai.</p>
                </div>
              ) : (
                complaints.filter(c => c.status === WorkflowStatus.FINISHED).map(c => (
                  <div key={c.id} className="p-5 bg-white dark:bg-gray-800 rounded-2xl border border-gray-100 dark:border-gray-700 flex justify-between items-center">
                    <div>
                      <p className="font-bold dark:text-white text-lg">Kamar {c.roomId}</p>
                      <p className="text-sm text-gray-500">{c.description}</p>
                    </div>
                    <div className="text-right">
                      <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-bold uppercase tracking-wider">Selesai</span>
                      <p className="text-[10px] text-gray-400 mt-2 font-bold uppercase">{c.date}</p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        );
      default:
        return <Dashboard rooms={rooms} complaints={complaints} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-gray-900">
      <Sidebar currentView={currentView} setView={setView} />
      <main className="flex-1 ml-72 min-h-screen transition-all">
        <Header title={getTitle()} />
        <div className="mx-auto max-w-7xl">
          {renderView()}
        </div>
      </main>

      {/* Modal Detail */}
      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={`Detail Keluhan Kamar ${selectedComplaint?.roomId}`}
      >
        {selectedComplaint && (
          <div className="space-y-6">
            <div className="flex flex-col sm:flex-row gap-6">
              <div className="w-full sm:w-1/2 aspect-square rounded-2xl overflow-hidden bg-gray-100 dark:bg-gray-900 border border-gray-100 dark:border-gray-700">
                {selectedComplaint.image ? (
                  <img src={selectedComplaint.image} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center text-gray-300">
                    <span className="material-symbols-outlined text-6xl">no_photography</span>
                    <span className="text-xs mt-2 uppercase font-bold tracking-widest">Tidak ada foto</span>
                  </div>
                )}
              </div>
              <div className="flex-1 space-y-4">
                <div>
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Kategori</label>
                  <p className="text-lg font-bold dark:text-white flex items-center gap-2">
                    <span className="material-symbols-outlined text-primary">
                      {selectedComplaint.type === 'Air' ? 'water_drop' : selectedComplaint.type === 'Listrik' ? 'bolt' : 'construction'}
                    </span>
                    {selectedComplaint.type}
                  </p>
                </div>
                <div>
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Status Saat Ini</label>
                  <div className="mt-1">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
                      selectedComplaint.status === WorkflowStatus.NEW ? 'bg-orange-100 text-primary-dark' : 
                      selectedComplaint.status === WorkflowStatus.PROCESS ? 'bg-amber-100 text-amber-700' :
                      'bg-emerald-100 text-emerald-600'
                    }`}>
                      {selectedComplaint.status}
                    </span>
                  </div>
                </div>
                <div>
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Tanggal Laporan</label>
                  <p className="text-sm font-semibold dark:text-gray-200">{selectedComplaint.date}</p>
                </div>
                <div>
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Pelapor</label>
                  <p className="text-sm font-semibold dark:text-gray-200">{selectedComplaint.reporter}</p>
                </div>
              </div>
            </div>
            <div className="bg-gray-50 dark:bg-gray-900 p-5 rounded-2xl border border-gray-100 dark:border-gray-800">
              <label className="text-[10px] font-bold text-primary uppercase tracking-widest block mb-2">Deskripsi Masalah</label>
              <p className="text-sm text-gray-700 dark:text-gray-300 leading-relaxed">
                {selectedComplaint.description}
              </p>
            </div>
            <div className="flex justify-end pt-4">
              <button 
                onClick={() => setIsModalOpen(false)}
                className="px-8 py-3 bg-gray-900 dark:bg-white dark:text-gray-900 text-white rounded-xl text-sm font-bold shadow-lg active:scale-95 transition-all"
              >
                Tutup Detail
              </button>
            </div>
          </div>
        )}
      </Modal>

      {/* Dark Mode Toggle */}
      <button 
        onClick={() => document.documentElement.classList.toggle('dark')}
        className="fixed bottom-6 right-6 z-[60] p-4 bg-white dark:bg-gray-800 rounded-full shadow-2xl border border-gray-100 dark:border-gray-700 flex items-center justify-center hover:scale-110 transition-transform active:scale-95 group"
      >
        <span className="material-symbols-outlined text-primary group-hover:rotate-12 transition-transform">dark_mode</span>
      </button>
    </div>
  );
};

export default App;

