export enum RoomStatus {
  NORMAL = 'Normal',
  COMPLAINT = 'Ada Keluhan',
  REPAIR = 'Dalam Pengerjaan',
  FINISHED = 'Selesai'
}

export enum ComplaintType {
  AIR = 'Air',
  LISTRIK = 'Listrik',
  BANGUNAN = 'Bangunan',
  LAINNYA = 'Lainnya'
}

export enum WorkflowStatus {
  NEW = 'Baru',
  PROCESS = 'Diproses',
  FINISHED = 'Selesai',
  URGENT = 'Sangat Mendesak'
}

export interface Complaint {
  id: string;
  roomId: number;
  date: string;
  type: ComplaintType;
  description: string;
  status: WorkflowStatus;
  technician?: string;
  deadline?: string;
  notes?: string;
  reporter?: string;
  image?: string;
  // Detail Pengerjaan Baru
  workSteps?: string;
  partsReplaced?: string;
}

export interface Room {
  id: number;
  status: RoomStatus;
  lastIssue?: string;
  image?: string;
}

export type ViewType = 'dashboard' | 'input' | 'history' | 'actions' | 'report';

import React, { useState } from 'react';
import { Complaint, WorkflowStatus } from '../types';
import { TECHNICIANS } from '../constants';

interface ComplaintActionsProps {
  complaints: Complaint[];
  onUpdateStatus: (id: string, nextStatus: WorkflowStatus, details?: Partial<Complaint>) => void;
  onViewDetail: (complaint: Complaint) => void;
  onPreviewReport: (complaint: Complaint) => void;
}

type FilterType = 'all' | 'pending' | 'finished';

export const ComplaintActions: React.FC<ComplaintActionsProps> = ({ 
  complaints, 
  onUpdateStatus, 
  onViewDetail,
  onPreviewReport 
}) => {
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [draftDetails, setDraftDetails] = useState<Record<string, Partial<Complaint>>>({});

  const handleDraftChange = (id: string, field: keyof Complaint, value: string) => {
    setDraftDetails(prev => ({
      ...prev,
      [id]: { ...prev[id], [field]: value }
    }));
  };

  const filteredComplaints = complaints.filter(complaint => {
    if (activeFilter === 'pending') {
      return complaint.status === WorkflowStatus.NEW || complaint.status === WorkflowStatus.PROCESS;
    }
    if (activeFilter === 'finished') {
      return complaint.status === WorkflowStatus.FINISHED;
    }
    return true; // 'all'
  });

  const getFilterButtonClass = (filter: FilterType) => {
    const base = "whitespace-nowrap px-6 py-2.5 rounded-full text-sm font-bold transition-all border";
    return activeFilter === filter
      ? `${base} bg-primary text-white border-primary shadow-lg shadow-orange-500/20 scale-105`
      : `${base} bg-white dark:bg-gray-800 text-gray-500 border-gray-200 dark:border-gray-700 hover:border-primary hover:text-primary`;
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-500">
      {/* Filter Bar */}
      <div className="flex items-center gap-4 mb-8 overflow-x-auto pb-4 no-scrollbar">
        <button onClick={() => setActiveFilter('all')} className={getFilterButtonClass('all')}>
          Semua Keluhan ({complaints.length})
        </button>
        <button onClick={() => setActiveFilter('pending')} className={getFilterButtonClass('pending')}>
          Perlu Tindakan ({complaints.filter(c => c.status !== WorkflowStatus.FINISHED).length})
        </button>
        <button onClick={() => setActiveFilter('finished')} className={getFilterButtonClass('finished')}>
          Selesai ({complaints.filter(c => c.status === WorkflowStatus.FINISHED).length})
        </button>
      </div>

      <div className="space-y-6">
        {filteredComplaints.length === 0 ? (
          <div className="text-center py-24 bg-white dark:bg-gray-800 rounded-3xl border border-dashed border-gray-200 dark:border-gray-700">
            <span className="material-symbols-outlined text-gray-300 text-6xl mb-4">inventory_2</span>
            <h3 className="text-gray-900 dark:text-white font-bold text-lg">Tidak Ada Laporan</h3>
            <p className="text-gray-500 text-sm">Gunakan filter lain atau buat laporan baru.</p>
          </div>
        ) : (
          filteredComplaints.map((complaint) => (
            <div key={complaint.id} className={`bg-white dark:bg-gray-800 border-l-4 ${complaint.status === WorkflowStatus.FINISHED ? 'border-l-emerald-500' : 'border-l-primary'} rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden hover:shadow-md transition-all`}>
              <div className="p-6">
                <div className="flex flex-col lg:flex-row lg:items-start justify-between gap-8">
                  {/* Bagian Kiri: Info & Deskripsi */}
                  <div className="flex-1 space-y-6">
                    <div className="flex gap-5">
                      <div className="w-16 h-16 shrink-0 bg-orange-50 dark:bg-orange-900/20 rounded-xl flex items-center justify-center">
                        <span className="material-symbols-outlined text-primary text-3xl">
                          {complaint.type === 'Air' ? 'water_drop' : complaint.type === 'Listrik' ? 'bolt' : 'construction'}
                        </span>
                      </div>
                      <div className="flex-1">
                        <div className="flex items-center gap-3 mb-1">
                          <h3 className="text-xl font-black dark:text-white">Kamar {complaint.roomId}</h3>
                          <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${
                            complaint.status === WorkflowStatus.NEW ? 'bg-rose-100 text-rose-700' : 
                            complaint.status === WorkflowStatus.PROCESS ? 'bg-amber-100 text-amber-700' :
                            'bg-emerald-100 text-emerald-700'
                          }`}>
                            {complaint.status}
                          </span>
                        </div>
                        <p className="text-xs text-gray-400 font-bold mb-2">{complaint.date} • {complaint.id}</p>
                        <p className="text-sm font-bold text-gray-800 dark:text-gray-100 leading-snug">"{complaint.description}"</p>
                      </div>
                    </div>

                    {/* Form Detail Pengerjaan (Hanya muncul jika sudah/sedang diproses) */}
                    {(complaint.status === WorkflowStatus.PROCESS || complaint.status === WorkflowStatus.FINISHED) && (
                      <div className="bg-gray-50 dark:bg-gray-900/50 p-5 rounded-2xl border border-gray-100 dark:border-gray-800 space-y-4 animate-in slide-in-from-top-2">
                        <div className="flex items-center gap-2 mb-2 text-primary">
                          <span className="material-symbols-outlined text-lg">engineering</span>
                          <h4 className="text-[11px] font-black uppercase tracking-wider">Laporan Hasil Pengerjaan</h4>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div>
                            <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">Langkah yang Diambil</label>
                            <textarea 
                              disabled={complaint.status === WorkflowStatus.FINISHED}
                              onChange={(e) => handleDraftChange(complaint.id, 'workSteps', e.target.value)}
                              defaultValue={complaint.workSteps}
                              className="w-full text-xs p-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-1 focus:ring-primary outline-none min-h-[80px]" 
                              placeholder="Misal: Bongkar kran, ganti seal karet, tes kebocoran..."
                            ></textarea>
                          </div>
                          <div>
                            <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">Material / Suku Cadang</label>
                            <textarea 
                              disabled={complaint.status === WorkflowStatus.FINISHED}
                              onChange={(e) => handleDraftChange(complaint.id, 'partsReplaced', e.target.value)}
                              defaultValue={complaint.partsReplaced}
                              className="w-full text-xs p-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-1 focus:ring-primary outline-none min-h-[80px]" 
                              placeholder="Misal: Seal Karet 1/2 inch, Lem Pipa..."
                            ></textarea>
                          </div>
                        </div>
                      </div>
                    )}

                    <div className="flex gap-3">
                      <button 
                        onClick={() => onPreviewReport(complaint)}
                        className="text-xs font-black text-gray-500 hover:text-primary flex items-center gap-1.5 px-3 py-1.5 bg-white dark:bg-gray-800 border border-gray-100 dark:border-gray-700 rounded-lg transition-all"
                      >
