                          </button>
                        ) : (
                          <div className="w-full py-3.5 bg-emerald-50 dark:bg-emerald-900/10 text-emerald-600 dark:text-emerald-400 text-xs font-black rounded-xl flex items-center justify-center gap-2 border border-emerald-100 dark:border-emerald-800/20">
