                          </div>
                        )}
                        {complaint.status === WorkflowStatus.PROCESS && (
                          <button 
                            onClick={() => onUpdateStatus(complaint.status, WorkflowStatus.PROCESS, draftDetails[complaint.id])}
                            className="w-full mt-2 py-2 text-primary text-[10px] font-black uppercase hover:underline"
                          >
