                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ViewType, Room, Complaint, RoomStatus, WorkflowStatus } from './types';
import { INITIAL_ROOMS, INITIAL_COMPLAINTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './views/Dashboard';
import { InputComplaint } from './views/InputComplaint';
import { ComplaintActions } from './views/ComplaintActions';
import { Report } from './views/Report';
import { Modal } from './components/Modal';
import { ReportPreview } from './components/ReportPreview';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [rooms, setRooms] = useState<Room[]>(INITIAL_ROOMS);
  const [complaints, setComplaints] = useState<Complaint[]>(INITIAL_COMPLAINTS);

  const [selectedComplaint, setSelectedComplaint] = useState<Complaint | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);

  const getTitle = () => {
    switch(currentView) {
      case 'dashboard': return 'Dashboard Monitoring';
      case 'input': return 'Input Keluhan Baru';
      case 'history': return 'Riwayat Keluhan';
      case 'actions': return 'Manajemen Tindakan';
      case 'report': return 'Laporan Pemeliharaan';
      default: return 'Senyuminn Kost';
    }
  };

  const handleAddComplaint = (newComplaint: Complaint) => {
    setComplaints(prev => [newComplaint, ...prev]);
    setRooms(prevRooms => prevRooms.map(room => 
      room.id === newComplaint.roomId 
        ? { ...room, status: RoomStatus.COMPLAINT, lastIssue: newComplaint.description }
        : room
    ));
    setView('dashboard');
  };

  const handleUpdateStatus = (id: string, nextStatus: WorkflowStatus, details?: Partial<Complaint>) => {
    setComplaints(prev => prev.map(c => {
      if (c.id === id) {
        const updated = { ...c, ...details, status: nextStatus };
        if (nextStatus === WorkflowStatus.FINISHED) {
          setRooms(prevRooms => prevRooms.map(room => room.id === c.roomId ? { ...room, status: RoomStatus.NORMAL, lastIssue: undefined } : room));
        } else if (nextStatus === WorkflowStatus.PROCESS) {
          setRooms(prevRooms => prevRooms.map(room => room.id === c.roomId ? { ...room, status: RoomStatus.REPAIR } : room));
        }
        return updated;
      }
      return c;
    }));
  };

  const openDetail = (complaint: Complaint) => {
    setSelectedComplaint(complaint);
    setIsModalOpen(true);
  };

  const openPreview = (complaint: Complaint) => {
    // Cari data terbaru dari state utama untuk memastikan detail pengerjaan terbawa
    const latest = complaints.find(c => c.id === complaint.id) || complaint;
    setSelectedComplaint(latest);
    setIsPreviewOpen(true);
  };

  const renderView = () => {
    switch(currentView) {
      case 'dashboard':
        return <Dashboard rooms={rooms} complaints={complaints} />;
      case 'input':
        return <InputComplaint onSave={handleAddComplaint} />;
      case 'actions':
        return (
          <ComplaintActions 
            complaints={complaints} 
            onUpdateStatus={handleUpdateStatus} 
            onViewDetail={openDetail} 
            onPreviewReport={openPreview} 
          />
        );
      case 'report':
        return <Report complaints={complaints} />;
      case 'history':
        return (
          <div className="p-10 space-y-6 animate-in fade-in duration-500">
            <h2 className="text-2xl font-bold dark:text-white">Riwayat Keluhan Selesai</h2>
            <div className="grid gap-4">
              {complaints.filter(c => c.status === WorkflowStatus.FINISHED).length === 0 ? (
                <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-2xl border border-dashed border-gray-200">
                   <p className="text-gray-400">Belum ada riwayat keluhan yang selesai.</p>
                </div>
              ) : (
                complaints.filter(c => c.status === WorkflowStatus.FINISHED).map(c => (
                  <div key={c.id} className="p-5 bg-white dark:bg-gray-800 rounded-2xl border border-gray-100 dark:border-gray-700 flex justify-between items-center">
                    <div>
                      <p className="font-bold dark:text-white text-lg">Kamar {c.roomId}</p>
                      <p className="text-sm text-gray-500 line-clamp-1">{c.description}</p>
                    </div>
                    <button 
                      onClick={() => openPreview(c)}
                      className="px-4 py-2 text-primary border border-primary/20 rounded-lg text-xs font-bold hover:bg-orange-50"
                    >
                      Lihat Laporan
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        );
      default:
        return <Dashboard rooms={rooms} complaints={complaints} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-gray-900">
      <Sidebar currentView={currentView} setView={setView} />
      <main className="flex-1 ml-72 min-h-screen transition-all">
        <Header title={getTitle()} />
        <div className="mx-auto max-w-7xl">
          {renderView()}
        </div>
      </main>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={`Detail Keluhan`}>
        {selectedComplaint && (
          <div className="space-y-6">
            <div className="flex flex-col sm:flex-row gap-6">
              <div className="w-full sm:w-1/2 aspect-square rounded-2xl overflow-hidden bg-gray-100">
                {selectedComplaint.image && <img src={selectedComplaint.image} className="w-full h-full object-cover" />}
              </div>
              <div className="flex-1 space-y-4">
                <p className="text-lg font-bold dark:text-white">Kamar {selectedComplaint.roomId}</p>
                <p className="text-sm text-gray-600 dark:text-gray-300">{selectedComplaint.description}</p>
                <div className="pt-4 border-t border-gray-100 dark:border-gray-700 space-y-2">
                  <span className="text-xs font-bold text-gray-400 block uppercase">STATUS: {selectedComplaint.status}</span>
                  {selectedComplaint.technician && <span className="text-xs text-gray-500 block">TEKNISI: {selectedComplaint.technician}</span>}
                </div>
              </div>
            </div>
            <button onClick={() => setIsModalOpen(false)} className="w-full py-3 bg-gray-900 text-white rounded-xl font-bold">Tutup</button>
          </div>
        )}
      </Modal>

      {isPreviewOpen && selectedComplaint && (
        <div className="fixed inset-0 z-[150] overflow-y-auto bg-gray-100/90 backdrop-blur-md">
          <ReportPreview 
            complaint={selectedComplaint} 
            onClose={() => setIsPreviewOpen(false)} 
          />
        </div>
      )}

      <button onClick={() => document.documentElement.classList.toggle('dark')} className="fixed bottom-6 right-6 z-[60] p-4 bg-white dark:bg-gray-800 rounded-full shadow-2xl border border-gray-100 dark:border-gray-700">
        <span className="material-symbols-outlined text-primary">dark_mode</span>
      </button>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Complaint, WorkflowStatus, ComplaintType } from '../types';
import { summarizeStatus } from '../services/gemini';

interface ReportProps {
  complaints: Complaint[];
}

export const Report: React.FC<ReportProps> = ({ complaints }) => {
  const [aiAnalysis, setAiAnalysis] = useState("Sedang menyusun laporan strategis...");
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    const fetchAnalysis = async () => {
      if (complaints.length === 0) {
        setAiAnalysis("Belum ada data untuk dianalisis.");
        return;
      }
      const summary = await summarizeStatus(complaints);
      setAiAnalysis(summary || "Gagal memproses data.");
    };
    fetchAnalysis();
  }, [complaints]);

  const solved = complaints.filter(c => c.status === WorkflowStatus.FINISHED).length;
  const solveRate = complaints.length > 0 ? Math.round((solved / complaints.length) * 100) : 0;

  const handleDownloadCSV = () => {
    setIsExporting(true);
    const headers = ['ID', 'Tanggal', 'Kamar', 'Tipe', 'Deskripsi', 'Status', 'Teknisi', 'Langkah Kerja', 'Material'];
    const rows = complaints.map(c => [
      c.id,
      c.date,
      c.roomId,
      c.type,
      `"${c.description.replace(/"/g, '""')}"`,
      c.status,
      c.technician || '-',
      `"${(c.workSteps || '-').replace(/"/g, '""')}"`,
      `"${(c.partsReplaced || '-').replace(/"/g, '""')}"`
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `Laporan_Senyuminn_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setTimeout(() => setIsExporting(false), 1000);
  };

  const handleDownloadPDF = () => {
    window.print();
  };

  return (
    <div className="p-4 md:p-8 space-y-8 animate-in fade-in duration-700 bg-white dark:bg-gray-900 min-h-screen">
      {/* Header Toolbar (Hidden on Print) */}
