          <h1 className="text-3xl font-extrabold text-gray-900 dark:text-white">Laporan Pemeliharaan Kost</h1>
          <p className="text-gray-500">Rekapitulasi data keluhan dan status pengerjaan seluruh unit.</p>
        </div>
        <div className="flex flex-wrap gap-3">
          <button 
            onClick={handleDownloadCSV}
            disabled={isExporting || complaints.length === 0}
            className="flex items-center gap-2 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-200 px-6 py-2.5 rounded-xl font-bold text-sm border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-all shadow-sm disabled:opacity-50"
          >
            <span className="material-symbols-outlined text-lg">{isExporting ? 'sync' : 'csv_entry'}</span>
            {isExporting ? 'Mengekspor...' : 'Unduh CSV'}
          </button>
          <button 
            onClick={handleDownloadPDF}
            className="flex items-center gap-2 bg-primary text-white px-6 py-2.5 rounded-xl font-bold text-sm hover:bg-primary-dark transition-all shadow-lg shadow-orange-500/20"
          >
            <span className="material-symbols-outlined text-lg">picture_as_pdf</span>
            Simpan PDF / Cetak
          </button>
        </div>
      </div>

      {/* Formal Document Layout */}
      <div id="report-document" className="bg-white dark:bg-gray-800 p-0 md:p-10 rounded-none md:rounded-3xl border-0 md:border border-gray-100 dark:border-gray-700 shadow-none md:shadow-xl max-w-5xl mx-auto">

        {/* Branding & Header (Formal Style) */}
        <div className="text-center border-b-2 border-primary/20 pb-8 mb-10">
          <div className="flex items-center justify-center gap-2 text-primary mb-2">
            <span className="material-symbols-outlined text-4xl">apartment</span>
            <h2 className="text-3xl font-black uppercase tracking-tighter">Senyuminn Kost</h2>
          </div>
          <h3 className="text-xl font-bold text-gray-800 dark:text-white uppercase tracking-tight">Laporan Keluhan & Pemeliharaan Unit</h3>
          <p className="text-sm text-gray-500 font-medium mt-1">
