const InputComplaint = ({ onSave }: { onSave: (c: Complaint) => void }) => {
  const [desc, setDesc] = useState('');
  const [rid, setRid] = useState('');
  const [type, setType] = useState<ComplaintType | ''>('');
  const [img, setImg] = useState<string | null>(null);
  const [tip, setTip] = useState('');
  const [loading, setLoading] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleSuggest = async () => { if (!desc) return; setLoading(true); const s = await suggestFix(desc); setTip(s || ''); setLoading(false); };
  const handleFile = (e: any) => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onloadend = () => setImg(r.result as string); r.readAsDataURL(f); } };
  const submit = () => {
    if (!rid || !type || !desc) return alert('Lengkapi data!');
    onSave({ id: `C${Date.now()}`, roomId: parseInt(rid), type: type as ComplaintType, description: desc, date: new Date().toLocaleDateString('id-ID'), status: WorkflowStatus.NEW, image: img || undefined });
  };

  return (
    <div className="max-w-4xl mx-auto p-8 space-y-8 animate-in slide-in-from-bottom-4">
      <h1 className="text-3xl font-black dark:text-white flex items-center gap-3"><span className="bg-primary/10 text-primary p-2 rounded-xl"><span className="material-symbols-outlined">add_task</span></span> Input Laporan</h1>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white dark:bg-gray-800 p-8 rounded-3xl border border-gray-100 dark:border-gray-700 space-y-6">
          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2"><label className="text-xs font-bold text-gray-500 uppercase">Kamar</label><select value={rid} onChange={e => setRid(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-gray-100 rounded-xl p-3 text-sm focus:ring-primary dark:text-white"><option value="">Pilih</option>{Array.from({length:12},(_,i)=><option key={i} value={i+1}>{i+1}</option>)}</select></div>
            <div className="space-y-2"><label className="text-xs font-bold text-gray-500 uppercase">Kategori</label><select value={type} onChange={e => setType(e.target.value as any)} className="w-full bg-gray-50 dark:bg-gray-900 border-gray-100 rounded-xl p-3 text-sm focus:ring-primary dark:text-white"><option value="">Pilih</option>{Object.values(ComplaintType).map(t=><option key={t} value={t}>{t}</option>)}</select></div>
          </div>
          <div className="space-y-3">
            <div className="flex justify-between items-center"><label className="text-xs font-bold text-gray-500 uppercase">Detail Masalah</label><button onClick={handleSuggest} disabled={loading||!desc} className="text-primary text-[10px] font-black hover:underline uppercase flex items-center gap-1">{loading ? '...' : 'Saran AI'}</button></div>
            <textarea rows={4} value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-gray-100 rounded-xl p-4 text-sm focus:ring-primary dark:text-white" placeholder="Deskripsikan masalah..."></textarea>
            {tip && <div className="p-4 bg-orange-50 dark:bg-orange-900/10 rounded-xl border border-orange-100 dark:border-orange-800/30 text-xs italic text-primary">"{tip}"</div>}
          </div>
        </div>
        <div className="space-y-6">
          <div onClick={() => fileRef.current?.click()} className="aspect-square bg-white dark:bg-gray-800 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-3xl flex flex-col items-center justify-center cursor-pointer hover:bg-orange-50 transition-all overflow-hidden">
            {img ? <img src={img} className="w-full h-full object-cover" /> : <><span className="material-symbols-outlined text-4xl text-gray-300">add_a_photo</span><p className="text-xs font-bold text-gray-400 mt-2 uppercase">Lampirkan Foto</p></>}
            <input type="file" ref={fileRef} onChange={handleFile} className="hidden" accept="image/*" />
          </div>
          <button onClick={submit} className="w-full bg-primary text-white font-black py-4 rounded-2xl shadow-xl shadow-orange-500/20 active:scale-95 transition-all">KIRIM LAPORAN</button>
        </div>
      </div>
    </div>
  );
};

const ComplaintActions = ({ complaints, onUpdateStatus, onPreviewReport }: { complaints: Complaint[], onUpdateStatus: any, onPreviewReport: any }) => {
  const [drafts, setDrafts] = useState<any>({});
  const updateDraft = (id: string, f: string, v: string) => setDrafts({...drafts, [id]: {...drafts[id], [f]: v}});
  return (
    <div className="p-8 space-y-6 animate-in fade-in">
      {complaints.filter(c => c.status !== WorkflowStatus.FINISHED).map(c => (
        <div key={c.id} className="bg-white dark:bg-gray-800 p-8 rounded-3xl border border-gray-100 dark:border-gray-700 shadow-sm flex gap-8">
          <div className="flex-1 space-y-6">
            <div className="flex justify-between">
              <div><h3 className="text-2xl font-black dark:text-white">Kamar {c.roomId}</h3><p className="text-xs text-gray-400 font-bold">{c.date} • {c.id}</p></div>
              <span className="px-3 py-1 bg-rose-50 text-rose-500 rounded-lg text-[10px] font-black uppercase h-fit">{c.status}</span>
            </div>
            <p className="text-sm font-bold dark:text-gray-300">"{c.description}"</p>
            <div className="grid grid-cols-2 gap-4 bg-gray-50 dark:bg-gray-900/50 p-5 rounded-2xl border border-gray-100">
              <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Langkah Kerja</label><textarea onChange={e => updateDraft(c.id, 'workSteps', e.target.value)} className="w-full bg-white dark:bg-gray-800 text-xs border rounded-xl p-3 h-24" placeholder="Apa yang diperbaiki?"></textarea></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Material</label><textarea onChange={e => updateDraft(c.id, 'partsReplaced', e.target.value)} className="w-full bg-white dark:bg-gray-800 text-xs border rounded-xl p-3 h-24" placeholder="Material yang digunakan?"></textarea></div>
            </div>
          </div>
          <div className="w-72 space-y-4">
            <div className="p-6 bg-gray-50 dark:bg-gray-900/50 rounded-2xl border border-gray-100">
              <label className="text-[10px] font-black text-gray-400 uppercase block mb-2">Pilih Teknisi</label>
              <select onChange={e => updateDraft(c.id, 'technician', e.target.value)} className="w-full text-xs bg-white dark:bg-gray-800 border rounded-lg p-2.5 mb-6">
                <option value="">-- Pilih --</option>{TECHNICIANS.map(t=><option key={t} value={t}>{t}</option>)}
              </select>
              <button onClick={() => onUpdateStatus(c.id, WorkflowStatus.FINISHED, drafts[c.id])} className="w-full py-4 bg-emerald-500 text-white text-xs font-black rounded-xl shadow-lg shadow-emerald-500/10 active:scale-95 transition-all">SELESAIKAN</button>
            </div>
            <button onClick={() => onPreviewReport(c)} className="w-full text-[10px] font-black text-gray-400 hover:text-primary uppercase tracking-widest transition-colors flex items-center justify-center gap-2"><span className="material-symbols-outlined text-sm">visibility</span> Pratinjau Dokumen</button>
          </div>
        </div>
      ))}
    </div>
  );
};

const Report = ({ complaints }: { complaints: Complaint[] }) => {
  const [isExp, setIsExp] = useState(false);
  const handleCSV = () => {
    setIsExp(true);
    const h = ['ID', 'Tgl', 'Unit', 'Tipe', 'Masalah', 'Status', 'Teknisi'];
    const r = complaints.map(c => [c.id, c.date, c.roomId, c.type, c.description, c.status, c.technician || '-']);
    const csv = [h.join(','), ...r.map(row => row.join(','))].join('\n');
    const b = new Blob([csv], { type: 'text/csv' });
    const u = URL.createObjectURL(b);
    const l = document.createElement('a');
    l.href = u; l.download = `Laporan_Kost_${new Date().toLocaleDateString()}.csv`; l.click();
    setTimeout(() => setIsExp(false), 1000);
  };
  return (
    <div className="p-8 space-y-8 bg-white dark:bg-gray-900">
      <div className="flex justify-between items-end print:hidden">
        <div><h1 className="text-3xl font-black dark:text-white">Laporan Pemeliharaan</h1><p className="text-gray-500">Rekapitulasi data operasional.</p></div>
        <div className="flex gap-4"><button onClick={handleCSV} disabled={isExp} className="px-6 py-2.5 bg-white border border-gray-200 text-xs font-bold rounded-xl">{isExp ? 'Processing...' : 'Ekspor CSV'}</button><button onClick={() => window.print()} className="px-6 py-2.5 bg-primary text-white text-xs font-bold rounded-xl shadow-lg shadow-orange-500/20">Cetak PDF</button></div>
      </div>
      <div className="bg-white border rounded-3xl p-10 max-w-5xl mx-auto shadow-sm">
        <div className="text-center border-b pb-8 mb-10"><h2 className="text-3xl font-black text-primary uppercase italic">Senyuminn Kost</h2><p className="text-sm font-bold text-gray-500 uppercase tracking-widest">Official Maintenance Report</p></div>
        <table className="w-full text-left border-collapse border-b border-gray-100">
          <thead><tr className="bg-gray-50 text-[10px] font-black uppercase text-gray-400 border-b border-gray-200"><th className="p-4">Tanggal</th><th className="p-4">Unit</th><th className="p-4">Kategori</th><th className="p-4">Masalah</th><th className="p-4 text-right">Status</th></tr></thead>
          <tbody className="divide-y divide-gray-100">{complaints.map(c => (
            <tr key={c.id} className="text-xs text-gray-700"><td className="p-4">{c.date}</td><td className="p-4 font-bold">Kamar {c.roomId}</td><td className="p-4">{c.type}</td><td className="p-4">{c.description}</td><td className="p-4 text-right font-black uppercase text-emerald-600">{c.status}</td></tr>
          ))}</tbody>
        </table>
      </div>
    </div>
  );
};

// ==========================================
// 6. MAIN APP COMPONENT
// ==========================================

const App = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [rooms, setRooms] = useState<Room[]>(() => { const s = localStorage.getItem(STORAGE_KEY_ROOMS); return s ? JSON.parse(s) : INITIAL_ROOMS; });
  const [complaints, setComplaints] = useState<Complaint[]>(() => { const s = localStorage.getItem(STORAGE_KEY_COMPLAINTS); return s ? JSON.parse(s) : INITIAL_COMPLAINTS; });
  const [selected, setSelected] = useState<Complaint | null>(null);
  const [isPreview, setIsPreview] = useState(false);

  useEffect(() => { localStorage.setItem(STORAGE_KEY_ROOMS, JSON.stringify(rooms)); }, [rooms]);
  useEffect(() => { localStorage.setItem(STORAGE_KEY_COMPLAINTS, JSON.stringify(complaints)); }, [complaints]);

  const handleAdd = (c: Complaint) => { setComplaints([c, ...complaints]); setRooms(rooms.map(r => r.id === c.roomId ? {...r, status: RoomStatus.COMPLAINT, lastIssue: c.description} : r)); setView('dashboard'); };
  const handleUpdate = (id: string, st: WorkflowStatus, det: any) => {
    setComplaints(complaints.map(c => c.id === id ? {...c, ...det, status: st} : c));
    const comp = complaints.find(c => c.id === id);
    if (st === WorkflowStatus.FINISHED && comp) setRooms(rooms.map(r => r.id === comp.roomId ? {...r, status: RoomStatus.NORMAL, lastIssue: undefined} : r));
  };
  const handleReset = () => { if (confirm('Hapus data lokal?')) { localStorage.clear(); setRooms(INITIAL_ROOMS); setComplaints(INITIAL_COMPLAINTS); setView('dashboard'); } };

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-gray-900">
      <Sidebar currentView={view} setView={setView} onResetData={handleReset} />
      <main className="flex-1 ml-72 min-h-screen transition-all">
        <Header title={view.toUpperCase()} />
        <div className="mx-auto max-w-7xl">
          {view === 'dashboard' && <Dashboard rooms={rooms} complaints={complaints} />}
          {view === 'input' && <InputComplaint onSave={handleAdd} />}
          {view === 'actions' && <ComplaintActions complaints={complaints} onUpdateStatus={handleUpdate} onPreviewReport={(c:any)=>{setSelected(c);setIsPreview(true);}} />}
          {view === 'report' && <Report complaints={complaints} />}
          {view === 'history' && (
            <div className="p-10 space-y-6 animate-in fade-in">
              <h2 className="text-2xl font-black dark:text-white uppercase tracking-tight">Riwayat Selesai</h2>
              <div className="grid gap-4">{complaints.filter(c => c.status === WorkflowStatus.FINISHED).map(c => (
                <div key={c.id} className="p-6 bg-white dark:bg-gray-800 rounded-3xl border border-gray-100 dark:border-gray-700 flex justify-between items-center">
                  <div><p className="font-bold dark:text-white">Kamar {c.roomId} • {c.date}</p><p className="text-xs text-gray-500">{c.description}</p></div>
                  <button onClick={()=>{setSelected(c);setIsPreview(true);}} className="px-6 py-2 bg-primary/10 text-primary rounded-xl text-xs font-black uppercase hover:bg-primary hover:text-white transition-all">Lihat Laporan</button>
                </div>
              ))}</div>
            </div>
          )}
        </div>
      </main>
      {isPreview && selected && <ReportPreview complaint={selected} onClose={()=>setIsPreview(false)} />}
      <button onClick={() => document.documentElement.classList.toggle('dark')} className="fixed bottom-6 right-6 z-[60] p-4 bg-white dark:bg-gray-800 rounded-full shadow-2xl border border-gray-100 print:hidden transition-transform active:scale-90"><span className="material-symbols-outlined text-primary">dark_mode</span></button>
    </div>
  );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<React.StrictMode><App /></React.StrictMode>);

import React, { useState, useEffect, useRef } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

// ==========================================
// 1. TYPES & INTERFACES
// ==========================================

export enum RoomStatus {
  NORMAL = 'Normal',
  COMPLAINT = 'Ada Keluhan',
  REPAIR = 'Dalam Pengerjaan',
  FINISHED = 'Selesai'
}

export enum ComplaintType {
  AIR = 'Air',
  LISTRIK = 'Listrik',
  BANGUNAN = 'Bangunan',
  LAINNYA = 'Lainnya'
}

export enum WorkflowStatus {
  NEW = 'Baru',
  PROCESS = 'Diproses',
  FINISHED = 'Selesai',
  URGENT = 'Sangat Mendesak'
}

export interface Complaint {
  id: string;
  roomId: number | string; // Diperbarui agar bisa menerima string (Fasum)
  date: string;
  type: ComplaintType;
  description: string;
  status: WorkflowStatus;
  technician?: string;
  deadline?: string;
  notes?: string;
  reporter?: string;
  image?: string;
  workSteps?: string;
  partsReplaced?: string;
}

export interface Room {
  id: number | string;
  status: RoomStatus;
  lastIssue?: string;
  image?: string;
}

export type ViewType = 'dashboard' | 'input' | 'history' | 'actions' | 'report';

// ==========================================
// 2. CONSTANTS
// ==========================================

const INITIAL_ROOMS: Room[] = Array.from({ length: 12 }, (_, i) => ({
  id: i + 1,
  status: RoomStatus.NORMAL,
  lastIssue: undefined,
  image: `https://picsum.photos/seed/room${i + 1}/400/225`
}));

const INITIAL_COMPLAINTS: Complaint[] = [];

const TECHNICIANS = [
  'Bp. Maman (Listrik/AC)',
  'Bp. Agus (Umum)',
  'Bp. Jono (Ledeng)'
];

const STORAGE_KEY_ROOMS = 'senyuminn_rooms_v2';
const STORAGE_KEY_COMPLAINTS = 'senyuminn_complaints_v2';

// ==========================================
// 3. AI SERVICES (GEMINI)
// ==========================================

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const suggestFix = async (description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Bertindaklah sebagai manajer kost berpengalaman. Berikan saran singkat (maks 20 kata) untuk menangani keluhan berikut: "${description}"`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Gagal mendapatkan saran AI.";
  }
};

const summarizeStatus = async (complaints: Complaint[]) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Berikan ringkasan eksekutif sangat singkat tentang status kost berdasarkan data keluhan ini: ${JSON.stringify(complaints)}. Gunakan nada profesional dan beri rekomendasi prioritas.`,
    });
    return response.text;
  } catch (error) {
    return "Gagal memproses ringkasan.";
  }
};

// ==========================================
// 4. COMMON COMPONENTS
// ==========================================

const Sidebar = ({ currentView, setView, onResetData }: { currentView: ViewType, setView: (v: ViewType) => void, onResetData: () => void }) => {
  const menuItems: { id: ViewType; label: string; icon: string }[] = [
    { id: 'dashboard', label: 'Dashboard', icon: 'dashboard' },
    { id: 'actions', label: 'Tindakan Keluhan', icon: 'assignment_turned_in' },
    { id: 'input', label: 'Input Keluhan', icon: 'add_circle' },
    { id: 'history', label: 'Riwayat', icon: 'history' },
    { id: 'report', label: 'Laporan', icon: 'description' },
  ];

  return (
    <aside className="w-72 bg-white dark:bg-gray-800 border-r border-gray-200 dark:border-gray-700 flex flex-col fixed h-full z-30 print:hidden transition-all">
      <div className="p-6">
        <div className="flex items-center gap-3 mb-8">
          <div className="bg-primary size-10 rounded-lg flex items-center justify-center text-white shadow-lg shadow-orange-500/20">
            <span className="material-symbols-outlined">apartment</span>
          </div>
