                <span className="material-symbols-outlined text-sm">calendar_today</span> Tanggal Kejadian
              </label>
              <input 
                type="date" 
                value={date} 
                onChange={e => setDate(e.target.value)} 
                className="w-full bg-gray-50 dark:bg-gray-900 border-gray-100 dark:border-gray-700 rounded-xl p-3 text-sm focus:ring-primary dark:text-white" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase flex items-center gap-2">
                <span className="material-symbols-outlined text-sm">meeting_room</span> Lokasi / Kamar
