            <div className="space-y-2 animate-in slide-in-from-top-2">
              <label className="text-xs font-bold text-gray-500 uppercase">Nama Area / Fasum</label>
              <input 
                type="text" 
                value={customArea} 
                onChange={e => setCustomArea(e.target.value)} 
