                className="w-full bg-orange-50/30 dark:bg-gray-900 border-primary/20 rounded-xl p-3 text-sm focus:ring-primary dark:text-white"
              />
            </div>
          )}

          {/* Baris 2: Kategori */}
          <div className="space-y-2">
            <label className="text-xs font-bold text-gray-500 uppercase">Kategori Keluhan</label>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
              {Object.values(ComplaintType).map(t => (
                <button 
                  key={t} 
