            <div className="flex justify-between items-center">
              <label className="text-xs font-bold text-gray-500 uppercase">Detail Masalah</label>
              <button onClick={handleSuggest} disabled={loading||!desc} className="text-primary text-[10px] font-black hover:underline uppercase flex items-center gap-1">
                <span className="material-symbols-outlined text-sm">auto_awesome</span>
                {loading ? 'Menganalisis...' : 'Saran AI'}
