            </div>
            <textarea rows={4} value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-gray-100 dark:border-gray-700 rounded-xl p-4 text-sm focus:ring-primary dark:text-white" placeholder="Contoh: Kran air bocor rembes ke tembok..."></textarea>
