// ==========================================

export enum RoomStatus {
  NORMAL = 'Normal',
  COMPLAINT = 'Ada Keluhan',
  REPAIR = 'Dalam Pengerjaan',
  FINISHED = 'Selesai'
}

export enum ComplaintType {
  AIR = 'Air',
  LISTRIK = 'Listrik',
  BANGUNAN = 'Bangunan',
  LAINNYA = 'Lainnya'
}

export enum WorkflowStatus {
  NEW = 'Baru',
  PROCESS = 'Diproses',
  FINISHED = 'Selesai',
  URGENT = 'Sangat Mendesak'
}

export interface Complaint {
  id: string;
  roomId: number | string;
  date: string;
  type: ComplaintType;
  description: string;
  status: WorkflowStatus;
  technician?: string;
  deadline?: string;
  notes?: string;
  reporter?: string;
  image?: string;
  workSteps?: string;
  partsReplaced?: string;
}

export interface Room {
  id: number | string;
  status: RoomStatus;
  lastIssue?: string;
  image?: string;
}

export type ViewType = 'dashboard' | 'input' | 'history' | 'actions' | 'report';

