                <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Material</label><textarea onChange={e => updateDraft(c.id, 'partsReplaced', e.target.value)} className="w-full bg-white dark:bg-gray-800 text-xs border rounded-xl p-3 h-24" placeholder="Material yang digunakan?"></textarea></div>
              </div>
            </div>
            <div className="w-72 space-y-4">
              <div className="p-6 bg-gray-50 dark:bg-gray-900/50 rounded-2xl border border-gray-100">
                <label className="text-[10px] font-black text-gray-400 uppercase block mb-2">Pilih Teknisi</label>
                <select onChange={e => updateDraft(c.id, 'technician', e.target.value)} className="w-full text-xs bg-white dark:bg-gray-800 border rounded-lg p-2.5 mb-6">
                  <option value="">-- Pilih --</option>{TECHNICIANS.map(t=><option key={t} value={t}>{t}</option>)}
                </select>
                <button onClick={() => onUpdateStatus(c.id, WorkflowStatus.FINISHED, drafts[c.id])} className="w-full py-4 bg-emerald-500 text-white text-xs font-black rounded-xl shadow-lg shadow-emerald-500/10 active:scale-95 transition-all">SELESAIKAN</button>
              </div>
              <button onClick={() => onPreviewReport(c)} className="w-full text-[10px] font-black text-gray-400 hover:text-primary uppercase tracking-widest transition-colors flex items-center justify-center gap-2"><span className="material-symbols-outlined text-sm">visibility</span> Pratinjau Dokumen</button>
            </div>
          </div>
        ))
      )}
