const Dashboard = ({ rooms, complaints }: { rooms: Room[], complaints: Complaint[] }) => {
  const [aiSummary, setAiSummary] = useState("Menganalisis status kost...");
  useEffect(() => { summarizeStatus(complaints).then(setAiSummary); }, [complaints]);
  const stats = [
    { label: 'Total Keluhan', value: complaints.length, icon: 'summarize', color: 'border-l-primary', bg: 'bg-orange-100 text-primary' },
    { label: 'Keluhan Baru', value: complaints.filter(c => c.status === WorkflowStatus.NEW).length, icon: 'report_problem', color: 'border-l-rose-500', bg: 'bg-rose-50 text-rose-500' },
    { label: 'Proses', value: complaints.filter(c => c.status === WorkflowStatus.PROCESS).length, icon: 'engineering', color: 'border-l-amber-500', bg: 'bg-amber-50 text-amber-500' },
    { label: 'Selesai', value: complaints.filter(c => c.status === WorkflowStatus.FINISHED).length, icon: 'check_circle', color: 'border-l-emerald-500', bg: 'bg-emerald-50 text-emerald-500' },
  ];
  return (
    <div className="p-8 space-y-8 animate-in fade-in">
      <div className="bg-gradient-to-r from-orange-500 to-orange-400 p-6 rounded-2xl text-white shadow-lg flex items-center gap-6">
        <div className="bg-white/20 p-4 rounded-full"><span className="material-symbols-outlined text-3xl">smart_toy</span></div>
        <div className="flex-1"><h3 className="font-bold text-lg">Analisis AI Senyuminn</h3><p className="text-sm opacity-90">{aiSummary}</p></div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {stats.map((s, i) => (
          <div key={i} className={`bg-white dark:bg-gray-800 p-6 rounded-xl border-l-4 ${s.color} border border-gray-100 dark:border-gray-700 shadow-sm transition-all hover:shadow-md`}>
            <div className={`p-2 ${s.bg} rounded-lg inline-block mb-4`}><span className="material-symbols-outlined">{s.icon}</span></div>
            <p className="text-gray-500 text-sm font-medium">{s.label}</p><p className="text-2xl font-bold dark:text-white">{s.value}</p>
          </div>
        ))}
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-4 gap-6">
        {rooms.map(r => (
          <div key={r.id} className="bg-white dark:bg-gray-800 rounded-xl border border-gray-100 dark:border-gray-700 p-5 border-t-4 border-t-primary transition-all hover:-translate-y-1">
            <div className="flex justify-between items-center mb-3"><h4 className="font-bold dark:text-white">{typeof r.id === 'number' ? `Kamar ${r.id}` : r.id}</h4><span className="px-2 py-0.5 bg-gray-50 dark:bg-gray-700 rounded text-[10px] font-bold text-gray-500 uppercase">{r.status}</span></div>
            <img src={r.image} className="w-full aspect-video object-cover rounded-lg mb-4" />
            <p className="text-xs text-gray-500 line-clamp-1">{r.lastIssue || 'Kondisi Baik'}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

const InputComplaint = ({ onSave }: { onSave: (c: Complaint) => void }) => {
  const [desc, setDesc] = useState('');
  const [rid, setRid] = useState('');
  const [customArea, setCustomArea] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<ComplaintType | ''>('');
  const [img, setImg] = useState<string | null>(null);
  const [tip, setTip] = useState('');
  const [loading, setLoading] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);
  const datePickerRef = useRef<HTMLInputElement>(null);

  const handleSuggest = async () => { if (!desc) return; setLoading(true); const s = await suggestFix(desc); setTip(s || ''); setLoading(false); };
  const handleFile = (e: any) => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onloadend = () => setImg(r.result as string); r.readAsDataURL(f); } };

  const submit = () => {
    const finalRoomId = rid === 'FASUM' ? (customArea || 'Fasum Umum') : parseInt(rid);
    if (!rid || !type || !desc) return alert('Lengkapi data!');
    if (rid === 'FASUM' && !customArea) return alert('Isi nama area fasum!');

    onSave({ 
      id: `C${Date.now()}`, 
      roomId: finalRoomId, 
      type: type as ComplaintType, 
      description: desc, 
      date: new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'short', year: 'numeric' }), 
      status: WorkflowStatus.NEW, 
      image: img || undefined 
    });
  };

  return (
    <div className="max-w-4xl mx-auto p-8 space-y-8 animate-in slide-in-from-bottom-4">
      <h1 className="text-3xl font-black dark:text-white flex items-center gap-3">
        <span className="bg-primary/10 text-primary p-2 rounded-xl">
          <span className="material-symbols-outlined text-3xl">add_task</span>
        </span> 
        Input Laporan Keluhan
      </h1>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white dark:bg-gray-800 p-8 rounded-3xl border border-gray-100 dark:border-gray-700 space-y-8">

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Custom Styled Date Picker Popup */}
            <div className="space-y-3">
              <label className="text-xs font-black text-gray-400 uppercase flex items-center gap-2">
                <span className="material-symbols-outlined text-sm text-primary">calendar_month</span> Tanggal Kejadian
              </label>
              <div 
                className="relative group cursor-pointer"
                onClick={() => datePickerRef.current?.showPicker()}
              >
                <div className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold flex justify-between items-center group-hover:border-primary transition-all">
                  <span className="dark:text-white">
                    {new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' })}
                  </span>
                  <span className="material-symbols-outlined text-primary">event</span>
                </div>
                <input 
                  type="date" 
                  ref={datePickerRef}
                  value={date} 
                  onChange={e => setDate(e.target.value)} 
                  className="absolute inset-0 opacity-0 cursor-pointer pointer-events-none" 
                />
              </div>
            </div>

            {/* Room Dropdown with FASUM option */}
            <div className="space-y-3">
              <label className="text-xs font-black text-gray-400 uppercase flex items-center gap-2">
                <span className="material-symbols-outlined text-sm text-primary">meeting_room</span> Nomor Kamar / Lokasi
              </label>
              <select 
                value={rid} 
                onChange={e => setRid(e.target.value)} 
                className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold focus:ring-primary dark:text-white appearance-none"
              >
                <option value="">-- Pilih --</option>
                {Array.from({length:12},(_,i)=><option key={i} value={i+1}>Kamar {i+1}</option>)}
                <option value="FASUM" className="text-primary font-black">Lainnya / Fasum (Input Manual)</option>
              </select>
            </div>
          </div>

          {/* Conditional Manual Input for Fasum */}
          {rid === 'FASUM' && (
            <div className="space-y-3 animate-in slide-in-from-top-4">
              <label className="text-xs font-black text-gray-400 uppercase">Nama Area / Fasilitas Umum</label>
              <input 
                type="text" 
                value={customArea} 
                onChange={e => setCustomArea(e.target.value)} 
                placeholder="Contoh: Area Parkir Depan, Dapur Umum Lt. 1..."
                className="w-full bg-orange-50/50 dark:bg-gray-900 border-2 border-primary/20 rounded-2xl p-4 text-sm font-bold focus:ring-primary dark:text-white"
              />
            </div>
          )}

          {/* Category Chips */}
          <div className="space-y-3">
            <label className="text-xs font-black text-gray-400 uppercase block">Kategori Masalah</label>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {Object.values(ComplaintType).map(t => (
                <button 
                  key={t} 
                  onClick={() => setType(t)}
                  className={`py-4 px-2 rounded-2xl text-[10px] font-black uppercase transition-all border-2 ${type === t ? 'bg-primary text-white border-primary shadow-xl shadow-orange-500/20 scale-105' : 'bg-gray-50 dark:bg-gray-900 text-gray-400 border-transparent hover:border-orange-100'}`}
                >
                  <span className="material-symbols-outlined block mb-1">
                    {t === 'Air' ? 'water_drop' : t === 'Listrik' ? 'bolt' : t === 'Bangunan' ? 'domain' : 'more_horiz'}
                  </span>
                  {t}
                </button>
              ))}
            </div>
          </div>

          {/* Description & AI */}
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <label className="text-xs font-black text-gray-400 uppercase">Detail Masalah</label>
              <button onClick={handleSuggest} disabled={loading||!desc} className="text-primary text-[10px] font-black hover:underline uppercase flex items-center gap-1.5 bg-orange-50 dark:bg-orange-900/10 px-3 py-1.5 rounded-full">
                <span className="material-symbols-outlined text-sm">auto_awesome</span>
                {loading ? 'AI Berpikir...' : 'Dapatkan Saran AI'}
              </button>
            </div>
            <textarea rows={5} value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-3xl p-5 text-sm font-medium focus:ring-primary dark:text-white" placeholder="Contoh: Kran air wastafel bocor parah..."></textarea>
            {tip && <div className="p-5 bg-orange-50 dark:bg-orange-900/10 rounded-2xl border border-orange-100 dark:border-orange-800/30 text-xs italic text-primary leading-relaxed shadow-sm">
              <span className="font-bold uppercase text-[9px] block mb-1 opacity-60">Saran Cepat AI:</span>
              "{tip}"
            </div>}
          </div>
        </div>

        <div className="space-y-8">
          {/* Photo Preview area */}
          <div onClick={() => fileRef.current?.click()} className="aspect-square bg-white dark:bg-gray-800 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer hover:bg-orange-50 hover:border-primary transition-all overflow-hidden shadow-sm">
            {img ? <img src={img} className="w-full h-full object-cover" /> : <><div className="bg-gray-50 p-6 rounded-full mb-4"><span className="material-symbols-outlined text-5xl text-gray-300">add_a_photo</span></div><p className="text-xs font-black text-gray-400 uppercase tracking-widest">Klik Ambil Foto</p></>}
            <input type="file" ref={fileRef} onChange={handleFile} className="hidden" accept="image/*" />
          </div>

          <button onClick={submit} className="w-full bg-primary text-white font-black py-5 rounded-3xl shadow-2xl shadow-orange-500/30 active:scale-95 transition-all uppercase tracking-[0.2em] text-xs">
            Kirim Laporan
          </button>
        </div>
      </div>
    </div>
  );
};

const ComplaintActions = ({ complaints, onUpdateStatus, onPreviewReport }: { complaints: Complaint[], onUpdateStatus: any, onPreviewReport: any }) => {
  const [drafts, setDrafts] = useState<any>({});
  const updateDraft = (id: string, f: string, v: string) => setDrafts({...drafts, [id]: {...drafts[id], [f]: v}});
  const pending = complaints.filter(c => c.status !== WorkflowStatus.FINISHED);

  return (
    <div className="p-8 space-y-6 animate-in fade-in">
      {pending.length === 0 ? (
        <div className="text-center py-24 bg-white dark:bg-gray-800 rounded-3xl border border-dashed border-gray-200">
          <span className="material-symbols-outlined text-gray-200 text-6xl mb-4">check_circle</span>
          <p className="text-gray-400 font-bold uppercase tracking-widest text-sm">Semua Keluhan Telah Selesai</p>
        </div>
      ) : (
        pending.map(c => (
          <div key={c.id} className="bg-white dark:bg-gray-800 p-8 rounded-3xl border border-gray-100 dark:border-gray-700 shadow-sm flex gap-8">
            <div className="flex-1 space-y-6">
              <div className="flex justify-between">
                <div><h3 className="text-2xl font-black dark:text-white uppercase">{typeof c.roomId === 'number' ? `Kamar ${c.roomId}` : c.roomId}</h3><p className="text-xs text-gray-400 font-bold">{c.date} • {c.id}</p></div>
                <span className={`px-3 py-1 ${c.status === WorkflowStatus.NEW ? 'bg-rose-50 text-rose-500' : 'bg-amber-50 text-amber-500'} rounded-lg text-[10px] font-black uppercase h-fit`}>{c.status}</span>
              </div>
              <p className="text-sm font-bold dark:text-gray-300 italic border-l-4 border-primary/20 pl-4">"{c.description}"</p>
              <div className="grid grid-cols-2 gap-4 bg-gray-50 dark:bg-gray-900/50 p-5 rounded-2xl border border-gray-100">
                <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Langkah Perbaikan</label><textarea onChange={e => updateDraft(c.id, 'workSteps', e.target.value)} className="w-full bg-white dark:bg-gray-800 text-xs border rounded-xl p-3 h-24" placeholder="Misal: Ganti bohlam LED baru..."></textarea></div>
                <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Material Terpakai</label><textarea onChange={e => updateDraft(c.id, 'partsReplaced', e.target.value)} className="w-full bg-white dark:bg-gray-800 text-xs border rounded-xl p-3 h-24" placeholder="Misal: Bohlam 10W, isolasi..."></textarea></div>
              </div>
            </div>
            <div className="w-72 space-y-4">
              <div className="p-6 bg-gray-50 dark:bg-gray-900/50 rounded-2xl border border-gray-100">
                <label className="text-[10px] font-black text-gray-400 uppercase block mb-2">Penugasan Teknisi</label>
                <select onChange={e => updateDraft(c.id, 'technician', e.target.value)} className="w-full text-xs bg-white dark:bg-gray-800 border rounded-lg p-2.5 mb-6">
                  <option value="">-- Pilih --</option>{TECHNICIANS.map(t=><option key={t} value={t}>{t}</option>)}
                </select>
                <button onClick={() => onUpdateStatus(c.id, WorkflowStatus.FINISHED, drafts[c.id])} className="w-full py-4 bg-emerald-500 text-white text-xs font-black rounded-xl shadow-lg shadow-emerald-500/10 active:scale-95 transition-all">SELESAIKAN</button>
              </div>
              <button onClick={() => onPreviewReport(c)} className="w-full text-[10px] font-black text-gray-400 hover:text-primary uppercase tracking-widest transition-colors flex items-center justify-center gap-2"><span className="material-symbols-outlined text-sm">visibility</span> Pratinjau Dokumen</button>
