// ==========================================
// 6. MAIN APP
// ==========================================

const App = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [rooms, setRooms] = useState<Room[]>(() => { const s = localStorage.getItem(STORAGE_KEY_ROOMS); return s ? JSON.parse(s) : INITIAL_ROOMS; });
  const [complaints, setComplaints] = useState<Complaint[]>(() => { const s = localStorage.getItem(STORAGE_KEY_COMPLAINTS); return s ? JSON.parse(s) : []; });
  const [selected, setSelected] = useState<Complaint | null>(null);
  const [isPreview, setIsPreview] = useState(false);

  useEffect(() => { localStorage.setItem(STORAGE_KEY_ROOMS, JSON.stringify(rooms)); }, [rooms]);
  useEffect(() => { localStorage.setItem(STORAGE_KEY_COMPLAINTS, JSON.stringify(complaints)); }, [complaints]);

  const handleAdd = (c: Complaint) => { 
    setComplaints([c, ...complaints]); 
    if (typeof c.roomId === 'number') {
      setRooms(rooms.map(r => r.id === c.roomId ? {...r, status: RoomStatus.COMPLAINT, lastIssue: c.description} : r)); 
    }
    setView('dashboard'); 
  };

  const handleUpdate = (id: string, st: WorkflowStatus, det: any) => {
    setComplaints(complaints.map(c => c.id === id ? {...c, ...det, status: st} : c));
    const comp = complaints.find(c => c.id === id);
    if (st === WorkflowStatus.FINISHED && comp && typeof comp.roomId === 'number') {
      setRooms(rooms.map(r => r.id === comp.roomId ? {...r, status: RoomStatus.NORMAL, lastIssue: undefined} : r));
    }
  };

  const handleReset = () => { if (confirm('Peringatan: Hapus seluruh database lokal?')) { localStorage.clear(); setRooms(INITIAL_ROOMS); setComplaints([]); setView('dashboard'); } };

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-gray-900 transition-colors">
      <Sidebar currentView={view} setView={setView} onResetData={handleReset} />
      <main className="flex-1 ml-72 min-h-screen">
        <Header title={view} />
        <div className="mx-auto max-w-7xl">
          {view === 'dashboard' && <Dashboard rooms={rooms} complaints={complaints} />}
          {view === 'input' && <InputComplaint onSave={handleAdd} />}
          {view === 'actions' && <ComplaintActions complaints={complaints} onUpdateStatus={handleUpdate} onPreviewReport={(c:any)=>{setSelected(c);setIsPreview(true);}} />}
          {view === 'report' && <Report complaints={complaints} />}
          {view === 'history' && (
            <div className="p-10 space-y-6 animate-in fade-in">
              <h2 className="text-2xl font-black dark:text-white uppercase tracking-tight">Riwayat Selesai</h2>
              <div className="grid gap-4">{complaints.filter(c => c.status === WorkflowStatus.FINISHED).map(c => (
                <div key={c.id} className="p-6 bg-white dark:bg-gray-800 rounded-3xl border border-gray-100 dark:border-gray-700 flex justify-between items-center transition-all hover:border-emerald-500/30">
                  <div><p className="font-bold dark:text-white uppercase">{typeof c.roomId === 'number' ? `Kamar ${c.roomId}` : c.roomId} • {c.date}</p><p className="text-xs text-gray-500">{c.description}</p></div>
                  <button onClick={()=>{setSelected(c);setIsPreview(true);}} className="px-6 py-2 bg-emerald-50 text-emerald-600 rounded-xl text-[10px] font-black uppercase hover:bg-emerald-500 hover:text-white transition-all tracking-widest">Detail Dokumen</button>
                </div>
              ))}</div>
            </div>
          )}
        </div>
      </main>
      {isPreview && selected && <ReportPreview complaint={selected} onClose={()=>setIsPreview(false)} />}
      <button onClick={() => document.documentElement.classList.toggle('dark')} className="fixed bottom-6 right-6 z-[60] p-4 bg-white dark:bg-gray-800 rounded-full shadow-2xl border border-gray-100 print:hidden transition-transform active:scale-90"><span className="material-symbols-outlined text-primary">dark_mode</span></button>
    </div>
  );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<React.StrictMode><App /></React.StrictMode>);

import React, { useState, useEffect, useRef } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

// ==========================================
// 1. TYPES & INTERFACES
// ==========================================

export enum RoomStatus {
  NORMAL = 'Normal',
  COMPLAINT = 'Ada Keluhan',
  REPAIR = 'Dalam Pengerjaan',
  FINISHED = 'Selesai'
}

export enum ComplaintType {
  AIR = 'Air',
  LISTRIK = 'Listrik',
  BANGUNAN = 'Bangunan',
  LAINNYA = 'Lainnya'
}

export enum WorkflowStatus {
  NEW = 'Baru',
  PROCESS = 'Diproses',
  FINISHED = 'Selesai',
  URGENT = 'Sangat Mendesak'
}

export interface Complaint {
  id: string;
  roomId: number | string;
  date: string;
  type: ComplaintType;
  description: string;
  status: WorkflowStatus;
  technician?: string;
  image?: string;
  workSteps?: string;
  partsReplaced?: string;
}

export interface Room {
  id: number | string;
  status: RoomStatus;
  lastIssue?: string;
  image?: string;
}

export type ViewType = 'dashboard' | 'input' | 'history' | 'actions' | 'report';

// ==========================================
// 2. CONSTANTS
// ==========================================

const INITIAL_ROOMS: Room[] = Array.from({ length: 12 }, (_, i) => ({
  id: i + 1,
  status: RoomStatus.NORMAL,
  lastIssue: undefined,
  image: `https://picsum.photos/seed/room${i + 1}/400/225`
}));

const TECHNICIANS = [
  'Bp. Maman (Listrik/AC)',
  'Bp. Agus (Umum)',
  'Bp. Jono (Ledeng)'
];

const STORAGE_KEY_ROOMS = 'senyuminn_rooms_v3';
const STORAGE_KEY_COMPLAINTS = 'senyuminn_complaints_v3';

// ==========================================
// 3. AI SERVICES (GEMINI)
// ==========================================

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const suggestFix = async (description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Bertindaklah sebagai manajer kost berpengalaman. Berikan saran singkat (maks 20 kata) untuk menangani keluhan berikut: "${description}"`,
    });
    return response.text;
  } catch (error) {
    return "Gagal mendapatkan saran AI.";
  }
};

const summarizeStatus = async (complaints: Complaint[]) => {
  try {
    if (complaints.length === 0) return "Dashboard bersih. Belum ada keluhan yang perlu dianalisis.";
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Berikan ringkasan eksekutif sangat singkat tentang status kost berdasarkan data keluhan ini: ${JSON.stringify(complaints)}.`,
    });
    return response.text;
  } catch (error) {
    return "Gagal memproses ringkasan.";
  }
};

// ==========================================
// 4. COMMON COMPONENTS
// ==========================================

const Sidebar = ({ currentView, setView, onResetData }: { currentView: ViewType, setView: (v: ViewType) => void, onResetData: () => void }) => {
