const InputComplaint = ({ onSave }: { onSave: (c: Complaint) => void }) => {
  const [desc, setDesc] = useState('');
  const [rid, setRid] = useState('');
  const [customArea, setCustomArea] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<ComplaintType | ''>('');
  const [img, setImg] = useState<string | null>(null);
  const [tip, setTip] = useState('');
  const [loading, setLoading] = useState(false);

  const fileRef = useRef<HTMLInputElement>(null);
  const dateInputRef = useRef<HTMLInputElement>(null);

  const handleSuggest = async () => { if (!desc) return; setLoading(true); const s = await suggestFix(desc); setTip(s || ''); setLoading(false); };
  const handleFile = (e: any) => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onloadend = () => setImg(r.result as string); r.readAsDataURL(f); } };

  const submit = () => {
    const finalRoomId = rid === 'FASUM' ? (customArea || 'Fasum') : parseInt(rid);
    if (!rid || !type || !desc) return alert('Lengkapi data laporan!');
    onSave({ 
      id: `C${Date.now()}`, 
      roomId: finalRoomId, 
      type: type as ComplaintType, 
      description: desc, 
      date: new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' }), 
      status: WorkflowStatus.NEW, 
      image: img || undefined 
    });
  };

  return (
    <div className="max-w-4xl mx-auto p-8 space-y-8 animate-in slide-in-from-bottom-4">
      <h1 className="text-3xl font-black dark:text-white flex items-center gap-3">
        <span className="bg-primary/10 text-primary p-2 rounded-xl"><span className="material-symbols-outlined text-3xl">add_task</span></span>
        Input Laporan
      </h1>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white dark:bg-gray-800 p-8 rounded-[2rem] border border-gray-100 dark:border-gray-700 space-y-8">

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Kalender Popup Trigger */}
            <div className="space-y-3">
              <label className="text-xs font-black text-gray-400 uppercase flex items-center gap-2"><span className="material-symbols-outlined text-sm text-primary">calendar_month</span> Tanggal Kejadian</label>
              <div className="relative group cursor-pointer" onClick={() => dateInputRef.current?.showPicker()}>
                <div className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold flex justify-between items-center group-hover:border-primary transition-all">
                  <span className="dark:text-white">
                    {new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' })}
                  </span>
                  <span className="material-symbols-outlined text-primary">event</span>
                </div>
                <input 
                  type="date" 
                  ref={dateInputRef} 
                  value={date} 
                  onChange={e => setDate(e.target.value)} 
                  className="absolute inset-0 opacity-0 cursor-pointer pointer-events-none" 
                />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-xs font-black text-gray-400 uppercase flex items-center gap-2"><span className="material-symbols-outlined text-sm text-primary">meeting_room</span> Nomor Kamar</label>
              <select value={rid} onChange={e => setRid(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold dark:text-white appearance-none">
                <option value="">-- Pilih --</option>
                {Array.from({length:12},(_,i)=><option key={i} value={i+1}>Kamar {i+1}</option>)}
                <option value="FASUM" className="text-primary">Fasum / Lainnya</option>
              </select>
            </div>
          </div>

          {rid === 'FASUM' && (
            <div className="space-y-3 animate-in slide-in-from-top-2">
              <label className="text-xs font-black text-gray-400 uppercase">Nama Area / Fasilitas</label>
              <input type="text" value={customArea} onChange={e => setCustomArea(e.target.value)} placeholder="Misal: Dapur Umum, Parkir Belakang..." className="w-full bg-orange-50/30 dark:bg-gray-900 border-2 border-primary/20 rounded-2xl p-4 text-sm font-bold dark:text-white focus:ring-primary" />
            </div>
          )}

          <div className="space-y-4">
            <div className="flex justify-between items-center"><label className="text-xs font-black text-gray-400 uppercase">Detail Masalah</label><button onClick={handleSuggest} disabled={loading||!desc} className="text-primary text-[10px] font-black uppercase flex items-center gap-1.5 bg-orange-50 dark:bg-orange-900/10 px-3 py-1.5 rounded-full"><span className="material-symbols-outlined text-sm">auto_awesome</span>{loading ? 'AI Berpikir...' : 'Saran AI'}</button></div>
            <textarea rows={5} value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-5 text-sm font-medium dark:text-white focus:ring-primary" placeholder="Kran wastafel patah dan bocor..."></textarea>
            {tip && <div className="p-4 bg-orange-50 dark:bg-orange-900/10 rounded-2xl border border-orange-100 text-xs italic text-primary leading-relaxed">"{tip}"</div>}
          </div>
        </div>

        <div className="space-y-6">
          <div onClick={() => fileRef.current?.click()} className="aspect-square bg-white dark:bg-gray-800 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer hover:bg-orange-50 transition-all overflow-hidden shadow-sm">
