              <div className="flex justify-between items-start">
                <div><h3 className="text-2xl font-black dark:text-white uppercase tracking-tighter">{typeof c.roomId === 'number' ? `Kamar ${c.roomId}` : c.roomId}</h3><p className="text-[10px] text-gray-400 font-bold tracking-widest uppercase">{c.date} • {c.id}</p></div>
                <span className={`px-3 py-1 ${c.status === WorkflowStatus.NEW ? 'bg-rose-50 text-rose-500' : 'bg-amber-50 text-amber-500'} rounded-lg text-[10px] font-black uppercase tracking-widest`}>{c.status}</span>
              </div>
              <p className="text-sm font-bold dark:text-gray-300 italic border-l-4 border-primary/20 pl-4">"{c.description}"</p>
              <div className="grid grid-cols-2 gap-4 bg-gray-50 dark:bg-gray-900/50 p-5 rounded-2xl">
                <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Langkah Kerja</label><textarea onChange={e => updateDraft(c.id, 'workSteps', e.target.value)} className="w-full bg-white dark:bg-gray-800 text-xs border-none rounded-xl p-3 h-24" placeholder="Misal: Ganti seal karet..."></textarea></div>
                <div className="space-y-2"><label className="text-[10px] font-black text-gray-400 uppercase">Material Terpakai</label><textarea onChange={e => updateDraft(c.id, 'partsReplaced', e.target.value)} className="w-full bg-white dark:bg-gray-800 text-xs border-none rounded-xl p-3 h-24" placeholder="Misal: Seal 1/2 inch..."></textarea></div>
              </div>
