const Dashboard = ({ rooms, complaints }: { rooms: Room[], complaints: Complaint[] }) => {
  const [aiSummary, setAiSummary] = useState("Menganalisis status kost...");
  useEffect(() => { summarizeStatus(complaints).then(setAiSummary); }, [complaints]);
  const stats = [
    { label: 'Total Keluhan', value: complaints.length, icon: 'summarize', bg: 'bg-orange-50 text-primary' },
    { label: 'Belum Ditangani', value: complaints.filter(c => c.status === WorkflowStatus.NEW).length, icon: 'report_problem', bg: 'bg-rose-50 text-rose-500' },
    { label: 'Proses Kerja', value: complaints.filter(c => c.status === WorkflowStatus.PROCESS).length, icon: 'engineering', bg: 'bg-amber-50 text-amber-500' },
    { label: 'Selesai', value: complaints.filter(c => c.status === WorkflowStatus.FINISHED).length, icon: 'check_circle', bg: 'bg-emerald-50 text-emerald-500' },
  ];
  return (
