        <div className="flex-1"><h3 className="font-bold text-lg mb-1 tracking-tight">Status Properti</h3><p className="text-sm opacity-90 leading-snug">{aiSummary}</p></div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {stats.map((s, i) => (
          <div key={i} className="bg-white dark:bg-gray-800 p-6 rounded-3xl border border-gray-100 dark:border-gray-700 shadow-sm">
            <div className={`p-2 ${s.bg} rounded-xl inline-block mb-4`}><span className="material-symbols-outlined">{s.icon}</span></div>
            <p className="text-gray-400 text-xs font-black uppercase tracking-widest mb-1">{s.label}</p><p className="text-2xl font-black dark:text-white">{s.value}</p>
          </div>
        ))}
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-4 gap-6">
        {rooms.map(r => (
          <div key={r.id} className="bg-white dark:bg-gray-800 rounded-3xl border border-gray-100 dark:border-gray-700 p-5 group transition-all hover:border-primary/50 shadow-sm">
            <div className="flex justify-between items-center mb-3"><h4 className="font-black dark:text-white uppercase text-xs">Kamar {r.id}</h4><span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${r.status === RoomStatus.NORMAL ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>{r.status}</span></div>
            <img src={r.image} className="w-full aspect-video object-cover rounded-2xl mb-4 group-hover:scale-[1.02] transition-transform" />
            <p className="text-[10px] text-gray-400 italic line-clamp-1">{r.lastIssue || 'Kondisi Baik'}</p>
          </div>
        ))}
