  return (
    <div className="p-8 space-y-6 animate-in fade-in">
      {pending.length === 0 ? (
        <div className="text-center py-24 bg-white dark:bg-gray-800 rounded-[3rem] border border-dashed border-gray-200 dark:border-gray-700 transition-all shadow-sm"><span className="material-symbols-outlined text-gray-200 dark:text-gray-700 text-7xl mb-4">task_alt</span><p className="text-gray-400 font-bold uppercase text-xs tracking-[0.2em]">Semua Unit Dalam Kondisi Baik</p></div>
