const InputComplaint = ({ onSave }: { onSave: (c: Complaint) => void }) => {
  const [desc, setDesc] = useState('');
  const [rid, setRid] = useState('');
  const [customArea, setCustomArea] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<ComplaintType | ''>('');
  const [img, setImg] = useState<string | null>(null);
  const [tip, setTip] = useState('');
  const [loading, setLoading] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const fileRef = useRef<HTMLInputElement>(null);

  const handleSuggest = async () => { if (!desc.trim()) return; setLoading(true); const s = await suggestFix(desc); setTip(s || ''); setLoading(false); };
  const handleFile = (e: any) => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onloadend = () => setImg(r.result as string); r.readAsDataURL(f); } };

  const submit = () => {
    if (isSubmitting) return;
    const finalRoomId = rid === 'FASUM' ? (customArea || 'Fasum') : parseInt(rid);
    if (!rid || !type || !desc) return alert('Mohon lengkapi Unit, Kategori, dan Deskripsi keluhan.');

    setIsSubmitting(true);

    const newComplaint: Complaint = { 
      id: `C${Date.now()}`, 
      roomId: finalRoomId, 
      type: type as ComplaintType, 
      description: desc, 
      date: new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' }), 
      status: WorkflowStatus.NEW, 
      image: img || undefined 
    };

    onSave(newComplaint);
  };

  return (
    <div className="max-w-4xl mx-auto p-8 space-y-8 animate-in slide-in-from-bottom-4">
      <h1 className="text-3xl font-black dark:text-white flex items-center gap-3">
        <span className="bg-primary/10 text-primary p-2 rounded-xl shadow-inner"><span className="material-symbols-outlined text-3xl">add_task</span></span>
        Input Laporan Keluhan
      </h1>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white dark:bg-gray-800 p-8 rounded-[2.5rem] border border-gray-100 dark:border-gray-700 space-y-8 shadow-sm">

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-3">
              <label className="text-xs font-black text-gray-400 uppercase flex items-center gap-2 tracking-widest"><span className="material-symbols-outlined text-sm text-primary">calendar_month</span> Tanggal Kejadian</label>
              <div className="relative group overflow-hidden rounded-2xl">
                <div className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold flex justify-between items-center group-hover:border-primary transition-all">
                  <span className="dark:text-white">
                    {new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' })}
                  </span>
                  <span className="material-symbols-outlined text-primary">event</span>
                </div>
                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="absolute inset-0 opacity-0 cursor-pointer z-10 w-full h-full" />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-xs font-black text-gray-400 uppercase flex items-center gap-2 tracking-widest"><span className="material-symbols-outlined text-sm text-primary">meeting_room</span> Unit / Kamar</label>
              <select value={rid} onChange={e => setRid(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold dark:text-white appearance-none focus:ring-1 focus:ring-primary outline-none">
                <option value="">-- Pilih Kamar --</option>
                {Array.from({length:12},(_,i)=><option key={i} value={i+1}>Kamar {i+1}</option>)}
                <option value="FASUM" className="text-primary font-bold">Fasum / Lainnya</option>
              </select>
            </div>
          </div>

          {rid === 'FASUM' && (
            <div className="space-y-3 animate-in slide-in-from-top-2">
              <label className="text-xs font-black text-gray-400 uppercase">Nama Area / Fasilitas</label>
              <input type="text" value={customArea} onChange={e => setCustomArea(e.target.value)} placeholder="Misal: Dapur Umum, Parkir Depan..." className="w-full bg-orange-50/30 dark:bg-gray-900 border-2 border-primary/20 rounded-2xl p-4 text-sm font-bold dark:text-white focus:ring-primary outline-none" />
            </div>
          )}

          <div className="space-y-4">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Kategori Masalah</label>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
              {Object.values(ComplaintType).map((ct) => (
                <button
                  key={ct}
                  onClick={() => setType(ct)}
                  className={`flex flex-col items-center justify-center py-4 rounded-2xl border-2 transition-all ${
                    type === ct 
                      ? 'bg-orange-50 border-primary text-primary shadow-sm' 
                      : 'bg-white dark:bg-gray-900 border-gray-100 dark:border-gray-700 text-gray-500 hover:border-orange-200'
                  }`}
                >
                  <span className="material-symbols-outlined mb-1">
                    {ct === 'Air' ? 'water_drop' : ct === 'Listrik' ? 'bolt' : ct === 'Bangunan' ? 'domain' : 'more_horiz'}
                  </span>
                  <span className="text-[10px] font-black uppercase tracking-tighter">{ct}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center"><label className="text-xs font-black text-gray-400 uppercase tracking-widest">Detail Masalah</label><button onClick={handleSuggest} disabled={loading||!desc} className="text-primary text-[10px] font-black uppercase flex items-center gap-1.5 bg-orange-50 dark:bg-orange-900/10 px-3 py-1.5 rounded-full hover:bg-orange-100 transition-colors"><span className="material-symbols-outlined text-sm">auto_awesome</span>{loading ? 'Menganalisis...' : 'Minta Saran AI'}</button></div>
            <textarea rows={5} value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-5 text-sm font-medium dark:text-white focus:ring-1 focus:ring-primary outline-none resize-none" placeholder="Ceritakan detail masalah..."></textarea>
            {tip && <div className="p-4 bg-orange-50 dark:bg-orange-900/10 rounded-2xl border border-orange-100 dark:border-orange-800/30 text-xs italic text-primary leading-relaxed animate-in slide-in-from-top-2">Saran AI: "{tip}"</div>}
          </div>
        </div>

        <div className="space-y-6">
          <div onClick={() => fileRef.current?.click()} className="aspect-square bg-white dark:bg-gray-800 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer hover:bg-orange-50 dark:hover:bg-gray-700 transition-all overflow-hidden shadow-sm group">
            {img ? <img src={img} className="w-full h-full object-cover" /> : <><div className="bg-gray-50 dark:bg-gray-900 p-6 rounded-full mb-4 group-hover:scale-110 transition-transform"><span className="material-symbols-outlined text-5xl text-gray-300">photo_camera</span></div><p className="text-xs font-black text-gray-400 uppercase tracking-widest text-center">Klik Untuk Ambil Bukti Foto</p></>}
            <input type="file" ref={fileRef} onChange={handleFile} className="hidden" accept="image/*" />
          </div>
          <button onClick={submit} disabled={isSubmitting} className="w-full bg-primary text-white font-black py-5 rounded-3xl shadow-xl shadow-orange-500/30 active:scale-95 transition-all uppercase tracking-widest text-xs hover:bg-primary-dark disabled:opacity-50">
            {isSubmitting ? 'MENYIMPAN...' : 'KIRIM LAPORAN SEKARANG'}
          </button>
        </div>
      </div>
    </div>
  );
};

