        <div className="lg:col-span-2 bg-white dark:bg-gray-800 p-8 rounded-[2.5rem] border border-gray-100 dark:border-gray-700 space-y-8 shadow-sm">

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-3">
              <label className="text-xs font-black text-gray-400 uppercase flex items-center gap-2 tracking-widest"><span className="material-symbols-outlined text-sm text-primary">calendar_month</span> Tanggal Kejadian</label>
              <div className="relative group overflow-hidden rounded-2xl">
                <div className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold flex justify-between items-center group-hover:border-primary transition-all">
                  <span className="dark:text-white">
                    {new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' })}
                  </span>
                  <span className="material-symbols-outlined text-primary">event</span>
                </div>
                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="absolute inset-0 opacity-0 cursor-pointer z-10 w-full h-full" />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-xs font-black text-gray-400 uppercase flex items-center gap-2 tracking-widest"><span className="material-symbols-outlined text-sm text-primary">meeting_room</span> Unit / Kamar</label>
              <select value={rid} onChange={e => setRid(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold dark:text-white appearance-none focus:ring-1 focus:ring-primary outline-none">
