            </div>
          )}

          <div className="space-y-4">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Kategori Masalah</label>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
              {Object.values(ComplaintType).map((ct) => (
                <button
                  key={ct}
                  onClick={() => setType(ct)}
                  className={`flex flex-col items-center justify-center py-4 rounded-2xl border-2 transition-all ${
                    type === ct 
                      ? 'bg-orange-50 border-primary text-primary shadow-sm' 
                      : 'bg-white dark:bg-gray-900 border-gray-100 dark:border-gray-700 text-gray-500 hover:border-orange-200'
                  }`}
                >
                  <span className="material-symbols-outlined mb-1">
                    {ct === 'Air' ? 'water_drop' : ct === 'Listrik' ? 'bolt' : ct === 'Bangunan' ? 'domain' : 'more_horiz'}
                  </span>
                  <span className="text-[10px] font-black uppercase tracking-tighter">{ct}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center"><label className="text-xs font-black text-gray-400 uppercase tracking-widest">Detail Masalah</label><button onClick={handleSuggest} disabled={loading||!desc} className="text-primary text-[10px] font-black uppercase flex items-center gap-1.5 bg-orange-50 dark:bg-orange-900/10 px-3 py-1.5 rounded-full hover:bg-orange-100 transition-colors"><span className="material-symbols-outlined text-sm">auto_awesome</span>{loading ? 'Menganalisis...' : 'Minta Saran AI'}</button></div>
            <textarea rows={5} value={desc} onChange={e => setDesc(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-5 text-sm font-medium dark:text-white focus:ring-1 focus:ring-primary outline-none resize-none" placeholder="Ceritakan detail masalah..."></textarea>
            {tip && <div className="p-4 bg-orange-50 dark:bg-orange-900/10 rounded-2xl border border-orange-100 dark:border-orange-800/30 text-xs italic text-primary leading-relaxed animate-in slide-in-from-top-2">Saran AI: "{tip}"</div>}
          </div>
        </div>

        <div className="space-y-6">
          <div onClick={() => fileRef.current?.click()} className="aspect-square bg-white dark:bg-gray-800 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer hover:bg-orange-50 dark:hover:bg-gray-700 transition-all overflow-hidden shadow-sm group">
            {img ? <img src={img} className="w-full h-full object-cover" /> : <><div className="bg-gray-50 dark:bg-gray-900 p-6 rounded-full mb-4 group-hover:scale-110 transition-transform"><span className="material-symbols-outlined text-5xl text-gray-300">photo_camera</span></div><p className="text-xs font-black text-gray-400 uppercase tracking-widest text-center">Klik Untuk Ambil Bukti Foto</p></>}
            <input type="file" ref={fileRef} onChange={handleFile} className="hidden" accept="image/*" />
          </div>
          <button onClick={submit} disabled={isSubmitting} className="w-full bg-primary text-white font-black py-5 rounded-3xl shadow-xl shadow-orange-500/30 active:scale-95 transition-all uppercase tracking-widest text-xs hover:bg-primary-dark disabled:opacity-50">
            {isSubmitting ? 'MENYIMPAN...' : 'KIRIM LAPORAN SEKARANG'}
          </button>
        </div>
      </div>
    </div>
  );
};

const ComplaintActions = ({ complaints, onUpdateStatus, onPreviewReport }: { complaints: Complaint[], onUpdateStatus: any, onPreviewReport: any }) => {
  const [activeFilter, setActiveFilter] = useState<WorkflowStatus | 'SEMUA'>('SEMUA');
  const [drafts, setDrafts] = useState<any>({});
  const updateDraft = (id: string, f: string, v: string) => setDrafts({...drafts, [id]: {...drafts[id], [f]: v}});

  const filtered = complaints.filter(c => {
    if (activeFilter === 'SEMUA') return true;
    return c.status === activeFilter;
  });

  const getFilterBtnClass = (status: WorkflowStatus | 'SEMUA') => {
    const isActive = activeFilter === status;
    return `px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${
      isActive ? 'bg-primary text-white shadow-lg shadow-orange-500/20' : 'bg-white dark:bg-gray-800 text-gray-400 border border-gray-100 dark:border-gray-700 hover:text-primary'
    }`;
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in">
      {/* Filter Bar */}
      <div className="flex flex-wrap gap-3 overflow-x-auto pb-2 no-scrollbar">
        <button onClick={() => setActiveFilter('SEMUA')} className={getFilterBtnClass('SEMUA')}>
          Semua ({complaints.length})
        </button>
        <button onClick={() => setActiveFilter(WorkflowStatus.NEW)} className={getFilterBtnClass(WorkflowStatus.NEW)}>
          Baru ({complaints.filter(c => c.status === WorkflowStatus.NEW).length})
        </button>
        <button onClick={() => setActiveFilter(WorkflowStatus.PROCESS)} className={getFilterBtnClass(WorkflowStatus.PROCESS)}>
          Proses ({complaints.filter(c => c.status === WorkflowStatus.PROCESS).length})
        </button>
        <button onClick={() => setActiveFilter(WorkflowStatus.FINISHED)} className={getFilterBtnClass(WorkflowStatus.FINISHED)}>
          Selesai ({complaints.filter(c => c.status === WorkflowStatus.FINISHED).length})
        </button>
      </div>

      <div className="space-y-6">
        {filtered.length === 0 ? (
          <div className="text-center py-24 bg-white dark:bg-gray-800 rounded-[3rem] border border-dashed border-gray-200 dark:border-gray-700 transition-all shadow-sm">
            <span className="material-symbols-outlined text-gray-200 dark:text-gray-700 text-7xl mb-4">inventory_2</span>
            <p className="text-gray-400 font-bold uppercase text-xs tracking-[0.2em]">Tidak Ada Laporan di Kategori Ini</p>
          </div>
        ) : (
          filtered.map(c => (
            <div key={c.id} className={`bg-white dark:bg-gray-800 p-8 rounded-[2rem] border border-gray-100 dark:border-gray-700 shadow-sm flex flex-col lg:flex-row gap-8 hover:shadow-md transition-shadow ${c.status === WorkflowStatus.FINISHED ? 'opacity-75' : ''}`}>
              <div className="flex-1 space-y-6">
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-2xl font-black dark:text-white uppercase tracking-tighter">
                      {typeof c.roomId === 'number' ? `Kamar ${c.roomId}` : c.roomId}
                    </h3>
                    <p className="text-[10px] text-gray-400 font-bold tracking-widest uppercase">{c.date} • ID: {c.id}</p>
                  </div>
                  <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest ${
                    c.status === WorkflowStatus.NEW ? 'bg-rose-50 text-rose-500' : 
                    c.status === WorkflowStatus.PROCESS ? 'bg-amber-50 text-amber-500' : 
                    'bg-emerald-50 text-emerald-500'
                  }`}>
                    {c.status}
                  </span>
                </div>

                <p className="text-sm font-bold dark:text-gray-300 italic border-l-4 border-primary/20 pl-4">"{c.description}"</p>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-gray-50 dark:bg-gray-900/50 p-5 rounded-2xl border border-gray-100 dark:border-gray-800">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Catatan Perbaikan</label>
                    <textarea 
                      readOnly={c.status === WorkflowStatus.FINISHED}
                      onChange={e => updateDraft(c.id, 'workSteps', e.target.value)} 
                      defaultValue={c.workSteps}
                      className="w-full bg-white dark:bg-gray-800 text-xs border-none rounded-xl p-3 h-24 focus:ring-1 focus:ring-primary outline-none" 
                      placeholder="Tindakan yang diambil..."
                    ></textarea>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Material Pengganti</label>
                    <textarea 
                      readOnly={c.status === WorkflowStatus.FINISHED}
                      onChange={e => updateDraft(c.id, 'partsReplaced', e.target.value)} 
                      defaultValue={c.partsReplaced}
                      className="w-full bg-white dark:bg-gray-800 text-xs border-none rounded-xl p-3 h-24 focus:ring-1 focus:ring-primary outline-none" 
                      placeholder="Daftar suku cadang..."
                    ></textarea>
                  </div>
                </div>
              </div>

              <div className="w-full lg:w-72 space-y-4">
                <div className="p-6 bg-gray-50 dark:bg-gray-900/50 rounded-2xl border border-gray-100 dark:border-gray-800">
                  <label className="text-[10px] font-black text-gray-400 uppercase block mb-2 tracking-widest">Nama Teknisi</label>
                  <input 
                    type="text" 
                    readOnly={c.status === WorkflowStatus.FINISHED}
                    placeholder="Ketik nama teknisi..."
                    defaultValue={c.technician}
                    onChange={e => updateDraft(c.id, 'technician', e.target.value)}
                    className="w-full text-xs bg-white dark:bg-gray-800 border-none rounded-lg p-2.5 mb-6 focus:ring-primary outline-none"
                  />

                  {c.status !== WorkflowStatus.FINISHED ? (
                    <button 
                      onClick={() => onUpdateStatus(
                        c.id, 
                        c.status === WorkflowStatus.NEW ? WorkflowStatus.PROCESS : WorkflowStatus.FINISHED, 
                        drafts[c.id]
                      )} 
                      className={`w-full py-4 text-white text-xs font-black rounded-xl shadow-lg active:scale-95 transition-all ${
                        c.status === WorkflowStatus.NEW ? 'bg-primary hover:bg-primary-dark shadow-orange-500/10' : 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-500/10'
                      }`}
                    >
                      {c.status === WorkflowStatus.NEW ? 'MULAI PENGERJAAN' : 'SELESAIKAN PEKERJAAN'}
                    </button>
                  ) : (
                    <div className="w-full py-4 bg-emerald-50 text-emerald-600 text-center text-xs font-black rounded-xl border border-emerald-100">
                      LAPORAN SELESAI
                    </div>
                  )}
                </div>
                <button onClick={() => onPreviewReport(c)} className="w-full text-[10px] font-black text-gray-400 hover:text-primary uppercase flex items-center justify-center gap-2 transition-colors">
                  <span className="material-symbols-outlined text-sm">visibility</span> Pratinjau Dokumen
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

const Report = ({ complaints }: { complaints: Complaint[] }) => (
  <div className="p-8 space-y-8 bg-white dark:bg-gray-900 min-h-screen animate-in fade-in">
    <div className="flex justify-between items-end print:hidden">
