// ==========================================

const App = () => {
  const [view, setView] = useState<ViewType>('dashboard');

  const [rooms, setRooms] = useState<Room[]>(() => { 
    const s = localStorage.getItem(STORAGE_KEY_ROOMS); 
    return s ? JSON.parse(s) : INITIAL_ROOMS; 
  });

  const [complaints, setComplaints] = useState<Complaint[]>(() => { 
    const s = localStorage.getItem(STORAGE_KEY_COMPLAINTS); 
    return s ? JSON.parse(s) : []; 
  });

  const [selected, setSelected] = useState<Complaint | null>(null);
  const [isPreview, setIsPreview] = useState(false);

  useEffect(() => { localStorage.setItem(STORAGE_KEY_ROOMS, JSON.stringify(rooms)); }, [rooms]);
  useEffect(() => { localStorage.setItem(STORAGE_KEY_COMPLAINTS, JSON.stringify(complaints)); }, [complaints]);

  const handleAdd = (c: Complaint) => { 
    setComplaints(prev => [c, ...prev]); 
    if (typeof c.roomId === 'number') {
      setRooms(prevRooms => prevRooms.map(r => 
        r.id === c.roomId ? {...r, status: RoomStatus.COMPLAINT, lastIssue: c.description} : r
      )); 
    }
    setView('dashboard'); 
  };

  const handleUpdate = (id: string, st: WorkflowStatus, det: any) => {
    setComplaints(prev => prev.map(c => c.id === id ? {...c, ...det, status: st} : c));
    const comp = complaints.find(c => c.id === id);
    if (comp && typeof comp.roomId === 'number') {
      if (st === WorkflowStatus.FINISHED) {
        setRooms(prevRooms => prevRooms.map(r => 
          r.id === comp.roomId ? {...r, status: RoomStatus.NORMAL, lastIssue: undefined} : r
        ));
      } else if (st === WorkflowStatus.PROCESS) {
        setRooms(prevRooms => prevRooms.map(r => 
          r.id === comp.roomId ? {...r, status: RoomStatus.REPAIR} : r
        ));
      }
    }
  };

  const handleReset = () => { if (confirm('Seluruh data lokal akan dihapus. Lanjutkan?')) { localStorage.clear(); window.location.reload(); } };

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-gray-900 transition-colors duration-500">
      <Sidebar currentView={view} setView={setView} onResetData={handleReset} />
      <main className="flex-1 ml-72 min-h-screen">
        <Header title={view === 'actions' ? 'Tindakan Keluhan' : view === 'input' ? 'Input Laporan' : view} />
        <div className="mx-auto max-w-7xl">
          {view === 'dashboard' && <Dashboard rooms={rooms} complaints={complaints} />}
          {view === 'input' && <InputComplaint onSave={handleAdd} />}
          {view === 'actions' && <ComplaintActions complaints={complaints} onUpdateStatus={handleUpdate} onPreviewReport={(c:any)=>{setSelected(c);setIsPreview(true);}} />}
          {view === 'report' && <Report complaints={complaints} />}
          {view === 'history' && (
            <div className="p-10 space-y-6 animate-in fade-in">
              <h2 className="text-2xl font-black dark:text-white uppercase tracking-tighter">Arsip Perbaikan</h2>
              <div className="grid gap-4">{complaints.filter(c => c.status === WorkflowStatus.FINISHED).length === 0 ? (
                <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-3xl border border-dashed border-gray-200">
                   <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest">Belum ada riwayat keluhan yang selesai.</p>
                </div>
              ) : (
                complaints.filter(c => c.status === WorkflowStatus.FINISHED).map(c => (
                  <div key={c.id} className="p-6 bg-white dark:bg-gray-800 rounded-3xl border border-gray-100 dark:border-gray-700 flex justify-between items-center group shadow-sm hover:border-emerald-500/30 transition-all">
                    <div><p className="font-bold dark:text-white uppercase text-sm tracking-tight">{typeof c.roomId === 'number' ? `Kamar ${c.roomId}` : c.roomId} • {c.date}</p><p className="text-xs text-gray-500 italic mt-1 line-clamp-1">"{c.description}"</p></div>
                    <button onClick={()=>{setSelected(c);setIsPreview(true);}} className="px-6 py-2 bg-emerald-50 text-emerald-600 rounded-xl text-[10px] font-black uppercase hover:bg-emerald-500 hover:text-white transition-all tracking-widest">Detail Laporan</button>
                  </div>
                ))
              )}</div>
            </div>
          )}
        </div>
      </main>
      {isPreview && selected && <ReportPreview complaint={selected} onClose={()=>setIsPreview(false)} />}
      <button onClick={() => document.documentElement.classList.toggle('dark')} className="fixed bottom-6 right-6 z-[60] p-4 bg-white dark:bg-gray-800 rounded-full shadow-2xl border border-gray-100 dark:border-gray-700 transition-all active:scale-90 hover:rotate-12"><span className="material-symbols-outlined text-primary">dark_mode</span></button>
    </div>
  );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<React.StrictMode><App /></React.StrictMode>);

export enum RoomStatus {
  NORMAL = 'Normal',
  COMPLAINT = 'Ada Keluhan',
  REPAIR = 'Dalam Pengerjaan',
  FINISHED = 'Selesai'
}

export enum ComplaintType {
  AIR = 'Air',
  LISTRIK = 'Listrik',
  BANGUNAN = 'Bangunan',
  LAINNYA = 'Lainnya'
}

export enum WorkflowStatus {
  NEW = 'Baru',
  PROCESS = 'Diproses',
  FINISHED = 'Selesai',
  URGENT = 'Sangat Mendesak'
}

export interface Complaint {
  id: string;
  roomId: number;
  date: string;
  finishedDate?: string;
  type: ComplaintType;
  description: string;
  status: WorkflowStatus;
  technician?: string;
  deadline?: string;
  notes?: string;
  reporter?: string;
  image?: string;
  // Detail Pengerjaan
  workSteps?: string;
  partsReplaced?: string;
}

export interface Room {
  id: number;
  status: RoomStatus;
  lastIssue?: string;
  image?: string;
}

export type ViewType = 'dashboard' | 'input' | 'history' | 'actions' | 'report';

import React, { useState, useEffect } from 'react';
import { ViewType, Room, Complaint, RoomStatus, WorkflowStatus } from './types';
import { INITIAL_ROOMS, INITIAL_COMPLAINTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './views/Dashboard';
import { InputComplaint } from './views/InputComplaint';
import { ComplaintActions } from './views/ComplaintActions';
import { Report } from './views/Report';
import { Modal } from './components/Modal';
import { ReportPreview } from './components/ReportPreview';

const STORAGE_KEY_ROOMS = 'senyuminn_rooms_v1';
const STORAGE_KEY_COMPLAINTS = 'senyuminn_complaints_v1';

const App: React.FC = () => {
  // Initialize state from LocalStorage or constants
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [rooms, setRooms] = useState<Room[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_ROOMS);
    return saved ? JSON.parse(saved) : INITIAL_ROOMS;
  });
  const [complaints, setComplaints] = useState<Complaint[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_COMPLAINTS);
    return saved ? JSON.parse(saved) : INITIAL_COMPLAINTS;
  });

  const [selectedComplaint, setSelectedComplaint] = useState<Complaint | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);

  // Sync states to LocalStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ROOMS, JSON.stringify(rooms));
  }, [rooms]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_COMPLAINTS, JSON.stringify(complaints));
  }, [complaints]);

  const getTitle = () => {
    switch(currentView) {
      case 'dashboard': return 'Dashboard Monitoring';
      case 'input': return 'Input Keluhan Baru';
      case 'history': return 'Riwayat Keluhan';
      case 'actions': return 'Manajemen Tindakan';
      case 'report': return 'Laporan Pemeliharaan';
      default: return 'Senyuminn Kost';
    }
  };

  const handleAddComplaint = (newComplaint: Complaint) => {
    setComplaints(prev => [newComplaint, ...prev]);
    setRooms(prevRooms => prevRooms.map(room => 
      room.id === newComplaint.roomId 
        ? { ...room, status: RoomStatus.COMPLAINT, lastIssue: newComplaint.description }
        : room
    ));
    setView('dashboard');
  };

  const handleUpdateStatus = (id: string, nextStatus: WorkflowStatus, details?: Partial<Complaint>) => {
    setComplaints(prev => prev.map(c => {
      if (c.id === id) {
        let finishedDate = c.finishedDate;
        if (nextStatus === WorkflowStatus.FINISHED && !finishedDate) {
          finishedDate = new Date().toLocaleDateString('id-ID', { 
            day: '2-digit', 
            month: 'short', 
            year: 'numeric' 
          });
        }

        const updated = { ...c, ...details, status: nextStatus, finishedDate };

        // Update room status side effect
        if (nextStatus === WorkflowStatus.FINISHED) {
          setRooms(prevRooms => prevRooms.map(room => room.id === c.roomId ? { ...room, status: RoomStatus.NORMAL, lastIssue: undefined } : room));
        } else if (nextStatus === WorkflowStatus.PROCESS) {
          setRooms(prevRooms => prevRooms.map(room => room.id === c.roomId ? { ...room, status: RoomStatus.REPAIR } : room));
        }
        return updated;
      }
      return c;
    }));
  };

  const handleResetData = () => {
    if (confirm('Apakah Anda yakin ingin menghapus semua data lokal? Tindakan ini tidak dapat dibatalkan.')) {
      localStorage.removeItem(STORAGE_KEY_ROOMS);
      localStorage.removeItem(STORAGE_KEY_COMPLAINTS);
      setRooms(INITIAL_ROOMS);
      setComplaints(INITIAL_COMPLAINTS);
      setView('dashboard');
    }
  };

  const openDetail = (complaint: Complaint) => {
    setSelectedComplaint(complaint);
    setIsModalOpen(true);
  };

  const openPreview = (complaint: Complaint) => {
    const latest = complaints.find(c => c.id === complaint.id) || complaint;
    setSelectedComplaint(latest);
    setIsPreviewOpen(true);
  };

  const renderView = () => {
    switch(currentView) {
      case 'dashboard':
        return <Dashboard rooms={rooms} complaints={complaints} />;
      case 'input':
        return <InputComplaint onSave={handleAddComplaint} />;
      case 'actions':
        return (
          <ComplaintActions 
            complaints={complaints} 
            onUpdateStatus={handleUpdateStatus} 
            onViewDetail={openDetail} 
            onPreviewReport={openPreview} 
          />
        );
      case 'report':
        return <Report complaints={complaints} />;
      case 'history':
        return (
          <div className="p-10 space-y-6 animate-in fade-in duration-500">
            <h2 className="text-2xl font-bold dark:text-white">Riwayat Keluhan Selesai</h2>
            <div className="grid gap-4">
              {complaints.filter(c => c.status === WorkflowStatus.FINISHED).length === 0 ? (
                <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-2xl border border-dashed border-gray-200">
                   <p className="text-gray-400">Belum ada riwayat keluhan yang selesai.</p>
                </div>
              ) : (
                complaints.filter(c => c.status === WorkflowStatus.FINISHED).map(c => (
                  <div key={c.id} className="p-5 bg-white dark:bg-gray-800 rounded-2xl border border-gray-100 dark:border-gray-700 flex justify-between items-center">
                    <div>
                      <p className="font-bold dark:text-white text-lg">Kamar {c.roomId}</p>
                      <p className="text-sm text-gray-500 line-clamp-1">{c.description}</p>
                    </div>
                    <button 
                      onClick={() => openPreview(c)}
                      className="px-4 py-2 text-primary border border-primary/20 rounded-lg text-xs font-bold hover:bg-orange-50"
                    >
                      Lihat Laporan
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        );
      default:
        return <Dashboard rooms={rooms} complaints={complaints} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-gray-900">
      <Sidebar currentView={currentView} setView={setView} onResetData={handleResetData} />
      <main className="flex-1 ml-72 min-h-screen transition-all">
        <Header title={getTitle()} />
        <div className="mx-auto max-w-7xl">
          {renderView()}
        </div>
      </main>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={`Detail Keluhan`}>
        {selectedComplaint && (
          <div className="space-y-6">
            <div className="flex flex-col sm:flex-row gap-6">
              <div className="w-full sm:w-1/2 aspect-square rounded-2xl overflow-hidden bg-gray-100">
                {selectedComplaint.image && <img src={selectedComplaint.image} className="w-full h-full object-cover" />}
              </div>
              <div className="flex-1 space-y-4">
                <p className="text-lg font-bold dark:text-white">Kamar {selectedComplaint.roomId}</p>
                <p className="text-sm text-gray-600 dark:text-gray-300">{selectedComplaint.description}</p>
                <div className="pt-4 border-t border-gray-100 dark:border-gray-700 space-y-2">
                  <span className="text-xs font-bold text-gray-400 block uppercase">STATUS: {selectedComplaint.status}</span>
                  {selectedComplaint.technician && <span className="text-xs text-gray-500 block">TEKNISI: {selectedComplaint.technician}</span>}
                </div>
              </div>
            </div>
            <button onClick={() => setIsModalOpen(false)} className="w-full py-3 bg-gray-900 text-white rounded-xl font-bold">Tutup</button>
          </div>
        )}
      </Modal>

      {isPreviewOpen && selectedComplaint && (
        <div className="fixed inset-0 z-[150] overflow-y-auto bg-gray-100/90 backdrop-blur-md">
          <ReportPreview 
            complaint={selectedComplaint} 
            onClose={() => setIsPreviewOpen(false)} 
          />
        </div>
      )}

      <button onClick={() => document.documentElement.classList.toggle('dark')} className="fixed bottom-6 right-6 z-[60] p-4 bg-white dark:bg-gray-800 rounded-full shadow-2xl border border-gray-100 dark:border-gray-700">
        <span className="material-symbols-outlined text-primary">dark_mode</span>
      </button>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Complaint, WorkflowStatus, ComplaintType } from '../types';
import { summarizeStatus } from '../services/gemini';

interface ReportProps {
  complaints: Complaint[];
}

export const Report: React.FC<ReportProps> = ({ complaints }) => {
  const [aiAnalysis, setAiAnalysis] = useState("Sedang menyusun laporan strategis...");
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    const fetchAnalysis = async () => {
      if (complaints.length === 0) {
        setAiAnalysis("Belum ada data untuk dianalisis.");
        return;
      }
      const summary = await summarizeStatus(complaints);
      setAiAnalysis(summary || "Gagal memproses data.");
    };
    fetchAnalysis();
  }, [complaints]);

  const solved = complaints.filter(c => c.status === WorkflowStatus.FINISHED).length;
  const solveRate = complaints.length > 0 ? Math.round((solved / complaints.length) * 100) : 0;

  const handleDownloadCSV = () => {
    setIsExporting(true);
    const headers = ['ID', 'Tgl Lapor', 'Tgl Selesai', 'Unit', 'Kategori', 'Masalah', 'Teknisi', 'Catatan Perbaikan', 'Material'];
    const rows = complaints.map(c => [
      c.id,
      c.date,
      c.finishedDate || '-',
      `Kamar ${c.roomId}`,
      c.type,
      `"${c.description.replace(/"/g, '""')}"`,
      c.technician || '-',
      `"${(c.workSteps || '-').replace(/"/g, '""')}"`,
      `"${(c.partsReplaced || '-').replace(/"/g, '""')}"`
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `Laporan_Senyuminn_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setTimeout(() => setIsExporting(false), 1000);
  };

  const handleDownloadPDF = () => {
    window.print();
  };

  return (
    <div className="p-4 md:p-8 space-y-8 animate-in fade-in duration-700 bg-white dark:bg-gray-900 min-h-screen">
      {/* Header Toolbar (Hidden on Print) */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 print:hidden">
        <div>
          <h1 className="text-3xl font-extrabold text-gray-900 dark:text-white">Laporan Pemeliharaan Kost</h1>
          <p className="text-gray-500">Rekapitulasi data keluhan dan status pengerjaan seluruh unit.</p>
        </div>
        <div className="flex flex-wrap gap-3">
          <button 
            onClick={handleDownloadCSV}
            disabled={isExporting || complaints.length === 0}
            className="flex items-center gap-2 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-200 px-6 py-2.5 rounded-xl font-bold text-sm border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 transition-all shadow-sm disabled:opacity-50"
          >
            <span className="material-symbols-outlined text-lg">{isExporting ? 'sync' : 'csv_entry'}</span>
