import React, { useState, useEffect, useRef } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

// ==========================================
// 1. TYPES & INTERFACES
// ==========================================

export enum RoomStatus {
  NORMAL = 'Normal',
  COMPLAINT = 'Ada Keluhan',
  REPAIR = 'Dalam Pengerjaan',
  FINISHED = 'Selesai'
}

export enum ComplaintType {
  AIR = 'Air',
  LISTRIK = 'Listrik',
  BANGUNAN = 'Bangunan',
  LAINNYA = 'Lainnya'
}

export enum WorkflowStatus {
  NEW = 'Baru',
  PROCESS = 'Diproses',
  FINISHED = 'Selesai',
  URGENT = 'Sangat Mendesak'
}

export interface Complaint {
  id: string;
  roomId: number | string;
  date: string;
  finishedDate?: string;
  type: ComplaintType;
  description: string;
  status: WorkflowStatus;
  technician?: string;
  image?: string;
  workSteps?: string;
  partsReplaced?: string;
}

export interface Room {
  id: number | string;
  status: RoomStatus;
  lastIssue?: string;
  image?: string;
}

export type ViewType = 'dashboard' | 'input' | 'history' | 'actions' | 'report';

// ==========================================
// 2. CONSTANTS
// ==========================================

const INITIAL_ROOMS: Room[] = Array.from({ length: 12 }, (_, i) => ({
  id: i + 1,
  status: RoomStatus.NORMAL,
  lastIssue: undefined,
  image: `https://picsum.photos/seed/room${i + 1}/400/225`
}));

const STORAGE_KEY_ROOMS = 'senyuminn_rooms_v3';
const STORAGE_KEY_COMPLAINTS = 'senyuminn_complaints_v3';

// ==========================================
// 3. AI SERVICES (GEMINI)
// ==========================================

const suggestFix = async (description: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Bertindaklah sebagai manajer kost berpengalaman. Berikan saran singkat (maks 20 kata) untuk menangani keluhan berikut: "${description}"`,
    });
    return response.text;
  } catch (error) {
    return "Gagal mendapatkan saran AI.";
  }
};

const summarizeStatus = async (complaints: Complaint[]) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    if (complaints.length === 0) return "Dashboard bersih. Belum ada keluhan yang perlu dianalisis.";
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Berikan ringkasan eksekutif sangat singkat tentang status kost berdasarkan data keluhan ini: ${JSON.stringify(complaints)}.`,
    });
    return response.text;
  } catch (error) {
    return "Gagal memproses ringkasan.";
  }
};

