          Semua ({complaints.length})
        </button>
        <button onClick={() => setActiveFilter(WorkflowStatus.NEW)} className={getFilterBtnClass(WorkflowStatus.NEW)}>
          Baru ({complaints.filter(c => c.status === WorkflowStatus.NEW).length})
