import React, { useState, useEffect } from 'react';
import { ViewType, Room, Complaint, RoomStatus, WorkflowStatus } from './types';
import { INITIAL_ROOMS, INITIAL_COMPLAINTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { Dashboard } from './views/Dashboard';
import { InputComplaint } from './views/InputComplaint';
import { ComplaintActions } from './views/ComplaintActions';
import { Report } from './views/Report';
import { Modal } from './components/Modal';
import { ReportPreview } from './components/ReportPreview';

const STORAGE_KEY_ROOMS = 'senyuminn_rooms_v3';
const STORAGE_KEY_COMPLAINTS = 'senyuminn_complaints_v3';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [rooms, setRooms] = useState<Room[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_ROOMS);
    return saved ? JSON.parse(saved) : INITIAL_ROOMS;
  });
  const [complaints, setComplaints] = useState<Complaint[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_COMPLAINTS);
    return saved ? JSON.parse(saved) : INITIAL_COMPLAINTS;
  });

  const [selectedComplaint, setSelectedComplaint] = useState<Complaint | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ROOMS, JSON.stringify(rooms));
  }, [rooms]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_COMPLAINTS, JSON.stringify(complaints));
  }, [complaints]);

  const handleAddComplaint = (newComplaint: Complaint) => {
    setComplaints(prev => [newComplaint, ...prev]);
    setRooms(prevRooms => prevRooms.map(room => 
      room.id === newComplaint.roomId 
        ? { ...room, status: RoomStatus.COMPLAINT, lastIssue: newComplaint.description }
        : room
    ));
    setView('dashboard');
  };

  const handleUpdateStatus = (id: string, nextStatus: WorkflowStatus, details?: Partial<Complaint>) => {
    setComplaints(prev => prev.map(c => {
      if (c.id === id) {
        let finishedDate = c.finishedDate;
        if (nextStatus === WorkflowStatus.FINISHED && !finishedDate) {
          finishedDate = new Date().toLocaleDateString('id-ID', { 
            day: '2-digit', 
            month: 'long', 
            year: 'numeric' 
          });
        }

        const updated = { ...c, ...details, status: nextStatus, finishedDate };

        if (nextStatus === WorkflowStatus.FINISHED) {
          setRooms(prevRooms => prevRooms.map(room => room.id === c.roomId ? { ...room, status: RoomStatus.NORMAL, lastIssue: undefined } : room));
        } else if (nextStatus === WorkflowStatus.PROCESS) {
          setRooms(prevRooms => prevRooms.map(room => room.id === c.roomId ? { ...room, status: RoomStatus.REPAIR } : room));
        }
        return updated;
      }
      return c;
    }));
  };

  const handleResetData = () => {
    if (confirm('Reset database?')) {
      localStorage.clear();
      window.location.reload();
    }
  };

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-gray-900 transition-colors">
      <Sidebar currentView={currentView} setView={setView} onResetData={handleResetData} />
      <main className="flex-1 ml-72 min-h-screen">
        <Header title={currentView.toUpperCase()} />
        <div className="mx-auto max-w-7xl">
          {currentView === 'dashboard' && <Dashboard rooms={rooms} complaints={complaints} />}
          {currentView === 'input' && <InputComplaint onSave={handleAddComplaint} />}
          {currentView === 'actions' && <ComplaintActions complaints={complaints} onUpdateStatus={handleUpdateStatus} onViewDetail={(c) => {setSelectedComplaint(c); setIsModalOpen(true);}} onPreviewReport={(c) => {setSelectedComplaint(c); setIsPreviewOpen(true);}} />}
          {currentView === 'report' && <Report complaints={complaints} />}
          {currentView === 'history' && (
             <div className="p-10 space-y-6">
               <h2 className="text-2xl font-black dark:text-white uppercase">Arsip Selesai</h2>
               <div className="grid gap-4">
                 {complaints.filter(c => c.status === WorkflowStatus.FINISHED).map(c => (
                   <div key={c.id} className="p-5 bg-white dark:bg-gray-800 rounded-2xl border border-gray-100 dark:border-gray-700 flex justify-between items-center">
                     <div><p className="font-bold dark:text-white">Kamar {c.roomId} - {c.date}</p></div>
                     <button onClick={() => {setSelectedComplaint(c); setIsPreviewOpen(true);}} className="text-primary font-bold text-xs uppercase">Lihat Laporan</button>
                   </div>
                 ))}
               </div>
             </div>
          )}
        </div>
      </main>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Detail Keluhan">
        {selectedComplaint && (
          <div className="space-y-4">
            <p className="font-bold">Kamar {selectedComplaint.roomId}</p>
            <p className="text-sm italic">"{selectedComplaint.description}"</p>
            {selectedComplaint.image && <img src={selectedComplaint.image} className="w-full h-48 object-cover rounded-xl" />}
          </div>
        )}
      </Modal>

      {isPreviewOpen && selectedComplaint && (
        <div className="fixed inset-0 z-[150] overflow-y-auto bg-gray-100/90 backdrop-blur-md">
          <ReportPreview complaint={selectedComplaint} onClose={() => setIsPreviewOpen(false)} />
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { ComplaintType, Complaint, WorkflowStatus } from '../types';
import { suggestFix } from '../services/gemini';

interface InputComplaintProps {
  onSave: (complaint: Complaint) => void;
}

export const InputComplaint: React.FC<InputComplaintProps> = ({ onSave }) => {
  const [description, setDescription] = useState('');
  const [roomId, setRoomId] = useState('');
  const [type, setType] = useState<ComplaintType | ''>('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [image, setImage] = useState<string | null>(null);
  const [aiTip, setAiTip] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSuggest = async () => {
    if (!description.trim()) return;
    setIsAiLoading(true);
    const suggestion = await suggestFix(description);
    setAiTip(suggestion || '');
    setIsAiLoading(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = () => {
    if (!roomId || !type || !description) return alert('Lengkapi data laporan.');
    onSave({
      id: `C${Date.now()}`,
      roomId: parseInt(roomId) || roomId,
      type: type as ComplaintType,
      description,
      date: new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'short', year: 'numeric' }),
      status: WorkflowStatus.NEW,
      image: image || undefined
    });
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 animate-in fade-in">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white dark:bg-gray-800 rounded-3xl p-8 shadow-sm border border-gray-100 dark:border-gray-700 space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">Tanggal Kejadian</label>
                <input 
                  type="date" 
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold dark:text-white focus:ring-1 focus:ring-primary outline-none"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block">Unit / Kamar</label>
                <select 
                  value={roomId}
                  onChange={(e) => setRoomId(e.target.value)}
                  className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-4 text-sm font-bold dark:text-white"
                >
                  <option value="">-- Pilih --</option>
                  {Array.from({ length: 12 }, (_, i) => <option key={i} value={i + 1}>Kamar {i + 1}</option>)}
                  <option value="FASUM">Area Umum</option>
                </select>
              </div>
            </div>

            <div className="space-y-4">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Kategori Masalah</label>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                {Object.values(ComplaintType).map((ct) => (
                  <button key={ct} onClick={() => setType(ct)} className={`py-4 rounded-2xl border-2 font-bold text-xs uppercase ${type === ct ? 'border-primary bg-orange-50 text-primary' : 'border-gray-50 dark:border-gray-700 text-gray-400'}`}>{ct}</button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Detail Masalah</label>
                <button onClick={handleSuggest} disabled={isAiLoading || !description} className="text-[10px] font-black text-primary bg-orange-50 px-3 py-1 rounded-full uppercase">Saran AI</button>
              </div>
              <textarea rows={4} value={description} onChange={(e) => setDescription(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-700 rounded-2xl p-5 text-sm" placeholder="Jelaskan masalahnya..."></textarea>
              {aiTip && <div className="p-4 bg-orange-50 dark:bg-orange-900/10 rounded-2xl border border-orange-100 text-xs italic text-primary">Saran AI: "{aiTip}"</div>}
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div onClick={() => fileInputRef.current?.click()} className="aspect-square bg-white dark:bg-gray-800 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer overflow-hidden shadow-sm group">
            {image ? <img src={image} className="w-full h-full object-cover" /> : <div className="text-center"><span className="material-symbols-outlined text-4xl text-gray-300 mb-2">add_a_photo</span><p className="text-[10px] font-black text-gray-400 uppercase">Ambil Foto Bukti</p></div>}
            <input type="file" accept="image/*" ref={fileInputRef} onChange={handleFileChange} className="hidden" />
          </div>
          <button onClick={handleSubmit} className="w-full bg-primary text-white font-black py-5 rounded-3xl shadow-xl shadow-orange-500/20 uppercase tracking-widest text-xs">Kirim Laporan</button>
        </div>
      </div>
    </div>
  );
};

