// ==========================================

const getAiService = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const suggestFix = async (description: string) => {
  try {
    const ai = getAiService();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Bertindaklah sebagai manajer kost. Berikan saran singkat (maks 15 kata) untuk: "${description}"`,
    });
    return response.text;
  } catch (e) { return "Gunakan teknisi ahli segera."; }
};

const summarizeStatus = async (complaints: Complaint[]) => {
  try {
    const ai = getAiService();
    if (complaints.length === 0) return "Kondisi kost sangat baik. Belum ada keluhan masuk.";
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ringkas status kost ini dalam 1 kalimat pendek: ${JSON.stringify(complaints)}`,
    });
    return response.text;
  } catch (e) { return "Status operasional terpantau normal."; }
};

