const InputView = ({ onSave }: { onSave: any }) => {
  const [desc, setDesc] = useState('');
  const [rid, setRid] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<ComplaintType | ''>('');
  const [img, setImg] = useState<string | null>(null);
  const [tip, setTip] = useState('');
  const [loading, setLoading] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleSuggest = async () => { if(!desc) return; setLoading(true); const s = await suggestFix(desc); setTip(s || ''); setLoading(false); };
  const handleFile = (e: any) => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onloadend = () => setImg(r.result as string); r.readAsDataURL(f); } };

  const submit = () => {
    if (!rid || !type || !desc) return alert('Lengkapi Form');
    onSave({ id: `C${Date.now()}`, roomId: rid, type, description: desc, date: new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' }), status: WorkflowStatus.NEW, image: img });
  };

  return (
    <div className="max-w-5xl mx-auto p-12 space-y-10 animate-in">
      <h1 className="text-3xl font-black dark:text-white flex items-center gap-4"><span className="p-3 bg-primary/10 text-primary rounded-2xl"><span className="material-symbols-outlined text-3xl">rate_review</span></span> Input Keluhan Baru</h1>
      <div className="grid grid-cols-3 gap-10">
        <div className="col-span-2 bg-white dark:bg-gray-800 p-10 rounded-[2.5rem] border border-gray-100 dark:border-gray-700 shadow-sm space-y-8">
          <div className="grid grid-cols-2 gap-8">
            <div className="space-y-3"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tgl Kejadian</label><input type="date" value={date} onChange={e=>setDate(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-4 text-sm font-bold dark:text-white" /></div>
            <div className="space-y-3"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Kamar Unit</label><select value={rid} onChange={e=>setRid(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-4 text-sm font-bold dark:text-white"><option value="">Pilih Kamar</option>{Array.from({length:12},(_,i)=><option key={i} value={i+1}>Kamar {i+1}</option>)}<option value="FASUM">Fasum</option></select></div>
          </div>
          <div className="space-y-4">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Kategori</label>
            <div className="grid grid-cols-4 gap-3">
              {Object.values(ComplaintType).map(ct => (
                <button key={ct} onClick={()=>setType(ct)} className={`py-4 rounded-2xl border-2 font-black text-[10px] uppercase transition-all ${type === ct ? 'bg-orange-50 border-primary text-primary shadow-sm' : 'bg-white dark:bg-gray-900 border-gray-50 dark:border-gray-700 text-gray-400'}`}>{ct}</button>
              ))}
            </div>
          </div>
          <div className="space-y-4">
            <div className="flex justify-between items-center"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Detail Keluhan</label><button onClick={handleSuggest} disabled={loading||!desc} className="bg-orange-50 text-primary text-[10px] font-black px-4 py-1.5 rounded-full uppercase flex items-center gap-2">{loading ? '...' : 'Tanya AI'}</button></div>
            <textarea rows={4} value={desc} onChange={e=>setDesc(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-5 text-sm dark:text-white" placeholder="Apa yang rusak?"></textarea>
            {tip && <div className="p-4 bg-orange-50 dark:bg-orange-900/10 rounded-2xl border border-orange-100 text-[11px] italic text-primary">AI: "{tip}"</div>}
          </div>
        </div>
        <div className="space-y-8">
          <div onClick={()=>fileRef.current?.click()} className="aspect-square bg-white dark:bg-gray-800 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-[2.5rem] flex flex-col items-center justify-center cursor-pointer overflow-hidden shadow-sm hover:bg-orange-50 transition-all">
            {img ? <img src={img} className="w-full h-full object-cover" /> : <div className="text-center"><span className="material-symbols-outlined text-4xl text-gray-300 mb-2">add_a_photo</span><p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Ambil Bukti Foto</p></div>}
            <input type="file" ref={fileRef} onChange={handleFile} className="hidden" accept="image/*" />
          </div>
          <button onClick={submit} className="w-full bg-primary text-white font-black py-5 rounded-3xl shadow-xl shadow-orange-500/20 active:scale-95 transition-all uppercase tracking-[0.2em] text-xs">Simpan Laporan</button>
        </div>
      </div>
    </div>
  );
};

