import React, { useState, useEffect, useRef } from 'react';
import ReactDOM from 'react-dom/client';
import { GoogleGenAI } from "@google/genai";

// --- Types & Enums ---
enum RoomStatus {
  NORMAL = 'Normal',
  COMPLAINT = 'Ada Keluhan',
  REPAIR = 'Dalam Pengerjaan',
}

enum ComplaintType {
  AIR = 'Air',
  LISTRIK = 'Listrik',
  BANGUNAN = 'Bangunan',
  LAINNYA = 'Lainnya'
}

enum WorkflowStatus {
  NEW = 'Baru',
  PROCESS = 'Diproses',
  FINISHED = 'Selesai'
}

interface Complaint {
  id: string;
  roomId: number | string;
  date: string;
  finishedDate?: string;
  type: ComplaintType;
  description: string;
  status: WorkflowStatus;
  technician?: string;
  image?: string;
  workSteps?: string;
  partsReplaced?: string;
}

interface Room {
  id: number | string;
  status: RoomStatus;
  lastIssue?: string;
  image?: string;
}

type ViewType = 'dashboard' | 'input' | 'actions' | 'report' | 'history';

// --- Constants ---
const INITIAL_ROOMS: Room[] = Array.from({ length: 12 }, (_, i) => ({
  id: i + 1,
  status: RoomStatus.NORMAL,
  lastIssue: undefined,
  image: `https://picsum.photos/seed/room${i + 1}/400/225`
}));

const TECHNICIANS = ['Bp. Maman (Umum)', 'Bp. Agus (Listrik/AC)', 'Bp. Jono (Ledeng)', 'Teknisi Luar'];
const STORAGE_KEY_ROOMS = 'senyuminn_rooms_prod';
const STORAGE_KEY_COMPLAINTS = 'senyuminn_complaints_prod';

// --- AI Services ---
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const suggestFix = async (description: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Bertindaklah sebagai manajer kost. Berikan saran singkat (maks 15 kata) untuk menangani keluhan: "${description}"`,
    });
    return response.text;
  } catch (e) { return "Segera panggil teknisi ahli."; }
};

const summarizeStatus = async (complaints: Complaint[]) => {
  try {
    const ai = getAI();
    if (complaints.length === 0) return "Operasional Kost sangat baik. Tidak ada keluhan tertunda.";
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Ringkas status operasional kost ini dalam 1 kalimat profesional: ${JSON.stringify(complaints)}`,
    });
    return response.text;
  } catch (e) { return "Sistem operasional berjalan normal."; }
};

// --- Sub-Components ---
const Sidebar = ({ currentView, setView, onReset }: { currentView: ViewType, setView: (v: ViewType) => void, onReset: () => void }) => (
