const App = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [rooms, setRooms] = useState<Room[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_ROOMS);
    return saved ? JSON.parse(saved) : INITIAL_ROOMS;
  });
  const [complaints, setComplaints] = useState<Complaint[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_COMPLAINTS);
    return saved ? JSON.parse(saved) : [];
  });
  const [selected, setSelected] = useState<Complaint | null>(null);

  useEffect(() => { localStorage.setItem(STORAGE_KEY_ROOMS, JSON.stringify(rooms)); }, [rooms]);
  useEffect(() => { localStorage.setItem(STORAGE_KEY_COMPLAINTS, JSON.stringify(complaints)); }, [complaints]);

  const handleAdd = (c: Complaint) => {
    setComplaints([c, ...complaints]);
    if (typeof c.roomId === 'number' || !isNaN(Number(c.roomId))) {
      setRooms(rooms.map(r => r.id == c.roomId ? { ...r, status: RoomStatus.COMPLAINT, lastIssue: c.description } : r));
    }
    setView('dashboard');
  };

  const handleUpdate = (id: string, st: WorkflowStatus, details: any) => {
    const finishedDate = st === WorkflowStatus.FINISHED ? new Date().toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' }) : undefined;
    const updated = complaints.map(c => c.id === id ? { ...c, ...details, status: st, finishedDate: finishedDate || c.finishedDate } : c);
    setComplaints(updated);
    const comp = updated.find(c => c.id === id);
    if (comp && comp.roomId) {
      if (st === WorkflowStatus.FINISHED) setRooms(rooms.map(r => r.id == comp.roomId ? { ...r, status: RoomStatus.NORMAL, lastIssue: undefined } : r));
      else if (st === WorkflowStatus.PROCESS) setRooms(rooms.map(r => r.id == comp.roomId ? { ...r, status: RoomStatus.REPAIR } : r));
    }
  };

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar currentView={view} setView={setView} onReset={() => { if(confirm('Hapus database permanen?')){ localStorage.clear(); window.location.reload(); }}} />
      <main className="flex-1 ml-72 flex flex-col h-full bg-background dark:bg-gray-900 transition-colors">
        <Header title={view === 'dashboard' ? 'Operational Dashboard' : view === 'input' ? 'Lapor Keluhan Baru' : view === 'actions' ? 'Tindakan Penanganan' : view === 'history' ? 'Arsip Keluhan' : 'Rekap Laporan'} />
        <div className="flex-1 overflow-y-auto no-scrollbar">
          {view === 'dashboard' && <DashboardView rooms={rooms} complaints={complaints} />}
          {view === 'input' && <InputView onSave={handleAdd} />}
          {view === 'actions' && <ActionView complaints={complaints} onUpdate={handleUpdate} onPreview={setSelected} />}
          {view === 'report' && <ReportView complaints={complaints} />}
          {view === 'history' && (
            <div className="p-10 space-y-8 animate-in">
              <h2 className="text-2xl font-black dark:text-white uppercase tracking-tight">Arsip Pekerjaan Selesai</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {complaints.filter(c => c.status === WorkflowStatus.FINISHED).map(c => (
                  <div key={c.id} className="p-8 bg-white dark:bg-gray-800 rounded-[2.5rem] border border-gray-100 dark:border-gray-700 flex justify-between items-center shadow-sm group hover:border-primary/40 transition-all">
                    <div>
                      <p className="font-black dark:text-white uppercase text-sm tracking-tight">Kamar {c.roomId} • {c.finishedDate}</p>
                      <p className="text-xs text-gray-400 mt-2 italic font-medium">"{c.description}"</p>
                    </div>
                    <button onClick={()=>setSelected(c)} className="px-6 py-3 bg-emerald-50 text-emerald-600 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-emerald-500 hover:text-white transition-all shadow-sm">Review PDF</button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>
      {selected && <ReportPreview complaint={selected} onClose={() => setSelected(null)} />}
    </div>
  );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

{
