    { label: 'Dalam Proses', value: complaints.filter(c => c.status === WorkflowStatus.PROCESS).length, icon: 'settings_suggest', color: 'text-amber-500' },
    { label: 'Sudah Selesai', value: complaints.filter(c => c.status === WorkflowStatus.FINISHED).length, icon: 'verified', color: 'text-emerald-500' },
  ];
  return (
    <div className="p-10 space-y-10 animate-in">
