const InputView = ({ onSave }: { onSave: (c: Complaint) => void }) => {
  const [desc, setDesc] = useState(''); const [rid, setRid] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<ComplaintType | ''>(''); const [img, setImg] = useState<string | null>(null);
  const [aiTip, setAiTip] = useState(''); const [loading, setLoading] = useState(false);
  const handleSuggest = async () => { if(!desc) return; setLoading(true); const tip = await suggestFix(desc); setAiTip(tip || ''); setLoading(false); };
  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => { const f = e.target.files?.[0]; if (f) { const reader = new FileReader(); reader.onloadend = () => setImg(reader.result as string); reader.readAsDataURL(f); } };
  return (
    <div className="max-w-5xl mx-auto p-12 space-y-10 animate-in">
      <h1 className="text-3xl font-black dark:text-white flex items-center gap-4"><span className="p-3 bg-primary/10 text-primary rounded-2xl"><span className="material-symbols-outlined text-3xl">add_box</span></span> Laporan Baru</h1>
      <div className="grid grid-cols-3 gap-10">
        <div className="col-span-2 bg-white dark:bg-gray-800 p-10 rounded-[3rem] border border-gray-100 dark:border-gray-700 shadow-sm space-y-8">
          <div className="grid grid-cols-2 gap-8">
            <div className="space-y-3"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tanggal</label><input type="date" value={date} onChange={e=>setDate(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-4 text-sm font-bold dark:text-white" /></div>
            <div className="space-y-3"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Kamar</label><select value={rid} onChange={e=>setRid(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-4 text-sm font-bold dark:text-white">{Array.from({length:12},(_,i)=><option key={i} value={i+1}>Kamar {i+1}</option>)}<option value="FASUM">Area Umum</option></select></div>
          </div>
          <div className="space-y-4"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Kategori</label><div className="grid grid-cols-4 gap-3">{Object.values(ComplaintType).map(ct => (<button key={ct} onClick={()=>setType(ct)} className={`py-4 rounded-2xl border-2 font-bold text-[10px] uppercase transition-all ${type === ct ? 'bg-orange-50 border-primary text-primary shadow-sm' : 'bg-white dark:bg-gray-900 border-gray-50 dark:border-gray-700 text-gray-400'}`}>{ct}</button>))}</div></div>
          <div className="space-y-4"><div className="flex justify-between items-center"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Detail Kerusakan</label><button onClick={handleSuggest} disabled={loading||!desc} className="bg-orange-50 text-primary text-[10px] font-black px-4 py-2 rounded-full uppercase tracking-widest">{loading ? '...' : 'Tanya AI'}</button></div><textarea rows={4} value={desc} onChange={e=>setDesc(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-6 text-sm dark:text-white" placeholder="Jelaskan kerusakannya..."></textarea>{aiTip && <div className="p-5 bg-orange-50 dark:bg-orange-900/10 rounded-2xl border border-orange-100 text-[11px] italic text-primary leading-relaxed">AI Manager: "{aiTip}"</div>}</div>
        </div>
        <div className="space-y-8"><div onClick={() => (document.getElementById('fileIn') as any).click()} className="aspect-square bg-white dark:bg-gray-800 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-[3rem] flex flex-col items-center justify-center cursor-pointer overflow-hidden shadow-sm">{img ? <img src={img} className="w-full h-full object-cover" /> : <div className="text-center"><span className="material-symbols-outlined text-5xl text-gray-300 mb-3">add_a_photo</span><p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Bukti Foto</p></div>}<input type="file" id="fileIn" onChange={handleFile} className="hidden" accept="image/*" /></div><button onClick={()=>onSave({ id: `C${Date.now()}`, roomId: rid, type: type as ComplaintType, description: desc, date: new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' }), status: WorkflowStatus.NEW, image: img || undefined })} className="w-full bg-primary text-white font-black py-6 rounded-3xl shadow-2xl shadow-orange-500/30 uppercase tracking-[0.2em] text-xs">Simpan Laporan</button></div>
      </div>
    </div>
  );
};

const ActionView = ({ complaints, onUpdate, onPreview }: { complaints: Complaint[], onUpdate: (id: string, st: WorkflowStatus, det: any) => void, onPreview: (c: Complaint) => void }) => {
  const [drafts, setDrafts] = useState<Record<string, any>>({});
  const updateDraft = (id: string, f: string, v: string) => setDrafts({...drafts, [id]: {...(drafts[id]||{}), [f]: v}});
  const filtered = complaints.filter(c => c.status !== WorkflowStatus.FINISHED);
  return (
    <div className="p-10 space-y-8 animate-in">
      {filtered.length === 0 ? (<div className="text-center py-40 bg-white dark:bg-gray-800 rounded-[3rem] border border-dashed border-gray-100 dark:border-gray-700"><span className="material-symbols-outlined text-gray-200 text-7xl mb-6">task_alt</span><p className="text-gray-400 font-black uppercase text-xs tracking-widest">Semua Keluhan Selesai</p></div>) : 
      filtered.map(c => (
        <div key={c.id} className="bg-white dark:bg-gray-800 p-8 rounded-[3rem] border border-gray-100 dark:border-gray-700 shadow-sm flex flex-col lg:flex-row gap-10 border-l-8 border-l-primary">
          <div className="flex-1 space-y-6">
            <div className="flex justify-between items-start"><div><h3 className="text-2xl font-black dark:text-white uppercase">Kamar {c.roomId}</h3><p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{c.date} • ID: {c.id}</p></div><span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${c.status === WorkflowStatus.NEW ? 'bg-rose-50 text-rose-500' : 'bg-amber-50 text-amber-500'}`}>{c.status}</span></div>
            <div className="p-6 bg-gray-50 dark:bg-gray-900 rounded-3xl italic text-sm text-gray-600 dark:text-gray-300">"{c.description}"</div>
            <div className="grid grid-cols-2 gap-4"><textarea onChange={e=>updateDraft(c.id, 'workSteps', e.target.value)} placeholder="Tindakan..." className="bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-5 text-xs h-28 focus:ring-2 focus:ring-primary dark:text-white"></textarea><textarea onChange={e=>updateDraft(c.id, 'partsReplaced', e.target.value)} placeholder="Material..." className="bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-5 text-xs h-28 focus:ring-2 focus:ring-primary dark:text-white"></textarea></div>
          </div>
          <div className="lg:w-80 space-y-6">
            <div className="p-8 bg-gray-50 dark:bg-gray-900 rounded-3xl space-y-5 border border-gray-100 dark:border-gray-800">
              <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Teknisi</label>
              <select onChange={e=>updateDraft(c.id, 'technician', e.target.value)} className="w-full bg-white dark:bg-gray-800 border-none rounded-xl text-xs font-bold py-3 shadow-sm">{TECHNICIANS.map(t=><option key={t} value={t}>{t}</option>)}</select>
              <button onClick={()=>onUpdate(c.id, c.status === WorkflowStatus.NEW ? WorkflowStatus.PROCESS : WorkflowStatus.FINISHED, drafts[c.id])} className={`w-full py-4 text-white text-xs font-black rounded-xl shadow-xl transition-all uppercase tracking-widest ${c.status === WorkflowStatus.NEW ? 'bg-primary' : 'bg-emerald-500 shadow-emerald-500/20'}`}>{c.status === WorkflowStatus.NEW ? 'Mulai Kerja' : 'Selesaikan'}</button>
            </div>
            <button onClick={()=>onPreview(c)} className="w-full text-[10px] font-black text-gray-400 hover:text-primary uppercase flex items-center justify-center gap-2 transition-all"><span className="material-symbols-outlined text-lg">visibility</span> Pratinjau Dokumen</button>
          </div>
        </div>
      ))}
    </div>
  );
