          <div className="space-y-4"><div className="flex justify-between items-center"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Detail Kerusakan</label><button onClick={handleSuggest} disabled={loading||!desc} className="bg-orange-50 text-primary text-[10px] font-black px-4 py-2 rounded-full uppercase tracking-widest">Tanya AI</button></div><textarea rows={4} value={desc} onChange={e=>setDesc(e.target.value)} className="w-full bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-6 text-sm dark:text-white" placeholder="Jelaskan kerusakannya..."></textarea>{aiTip && <div className="p-5 bg-orange-50 dark:bg-orange-900/10 rounded-2xl border border-orange-100 text-[11px] italic text-primary">AI: "{aiTip}"</div>}</div>
        </div>
        <div className="space-y-8"><div onClick={() => (document.getElementById('fileIn') as any).click()} className="aspect-square bg-white dark:bg-gray-800 border-2 border-dashed border-gray-100 dark:border-gray-700 rounded-[3rem] flex flex-col items-center justify-center cursor-pointer overflow-hidden shadow-sm">{img ? <img src={img} className="w-full h-full object-cover" /> : <div className="text-center"><span className="material-symbols-outlined text-5xl text-gray-300 mb-3">add_a_photo</span><p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Bukti Foto</p></div>}<input type="file" id="fileIn" onChange={handleFile} className="hidden" accept="image/*" /></div><button onClick={()=>onSave({ id: `C${Date.now()}`, roomId: rid, type: type as ComplaintType, description: desc, date: new Date(date).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' }), status: WorkflowStatus.NEW, image: img || undefined })} className="w-full bg-primary text-white font-black py-6 rounded-3xl shadow-xl uppercase tracking-widest text-xs">Simpan Laporan</button></div>
      </div>
    </div>
  );
};

const ActionView = ({ complaints, onUpdate, onPreview }: { complaints: Complaint[], onUpdate: (id: string, st: WorkflowStatus, det: any) => void, onPreview: (c: Complaint) => void }) => {
  const [drafts, setDrafts] = useState<Record<string, any>>({});
  const updateDraft = (id: string, f: string, v: string) => setDrafts({...drafts, [id]: {...(drafts[id]||{}), [f]: v}});
  const filtered = complaints.filter(c => c.status !== WorkflowStatus.FINISHED);
  return (
    <div className="p-10 space-y-8 animate-in">
      {filtered.length === 0 ? (<div className="text-center py-40 bg-white dark:bg-gray-800 rounded-[3rem] border border-dashed border-gray-100 dark:border-gray-700"><p className="text-gray-400 font-black uppercase text-xs tracking-widest">Tidak ada keluhan tertunda</p></div>) : 
      filtered.map(c => (
        <div key={c.id} className="bg-white dark:bg-gray-800 p-8 rounded-[3rem] border border-gray-100 dark:border-gray-700 shadow-sm flex flex-col lg:flex-row gap-10 border-l-8 border-l-primary">
          <div className="flex-1 space-y-6">
            <div className="flex justify-between items-start"><div><h3 className="text-2xl font-black dark:text-white uppercase">Kamar {c.roomId}</h3><p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{c.date}</p></div><span className="px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest bg-amber-50 text-amber-500">{c.status}</span></div>
            <div className="p-6 bg-gray-50 dark:bg-gray-900 rounded-3xl italic text-sm text-gray-600 dark:text-gray-300">"{c.description}"</div>
            <div className="grid grid-cols-2 gap-4"><textarea onChange={e=>updateDraft(c.id, 'workSteps', e.target.value)} placeholder="Tindakan..." className="bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-5 text-xs h-28 dark:text-white"></textarea><textarea onChange={e=>updateDraft(c.id, 'partsReplaced', e.target.value)} placeholder="Material..." className="bg-gray-50 dark:bg-gray-900 border-none rounded-2xl p-5 text-xs h-28 dark:text-white"></textarea></div>
          </div>
          <div className="lg:w-80 space-y-6">
            <div className="p-8 bg-gray-50 dark:bg-gray-900 rounded-3xl space-y-5">
              <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Teknisi</label>
              <select onChange={e=>updateDraft(c.id, 'technician', e.target.value)} className="w-full bg-white dark:bg-gray-800 border-none rounded-xl text-xs font-bold py-3">{TECHNICIANS.map(t=><option key={t} value={t}>{t}</option>)}</select>
              <button onClick={()=>onUpdate(c.id, c.status === WorkflowStatus.NEW ? WorkflowStatus.PROCESS : WorkflowStatus.FINISHED, drafts[c.id])} className={`w-full py-4 text-white text-xs font-black rounded-xl uppercase tracking-widest ${c.status === WorkflowStatus.NEW ? 'bg-primary' : 'bg-emerald-500'}`}>{c.status === WorkflowStatus.NEW ? 'Mulai Kerja' : 'Selesaikan'}</button>
            </div>
            <button onClick={()=>onPreview(c)} className="w-full text-[10px] font-black text-gray-400 hover:text-primary uppercase flex items-center justify-center gap-2 transition-all">Pratinjau Dokumen</button>
          </div>
        </div>
      ))}
    </div>
  );
};

const ReportView = ({ complaints }: { complaints: Complaint[] }) => (
  <div className="p-10 space-y-10 animate-in">
    <div className="flex justify-between items-end print:hidden"><div><h1 className="text-3xl font-black dark:text-white uppercase tracking-tight">Rekap Operasional</h1></div><button onClick={()=>window.print()} className="px-10 py-4 bg-primary text-white text-xs font-black rounded-2xl shadow-xl uppercase tracking-widest">Cetak Laporan</button></div>
    <div className="bg-white border rounded-[3rem] p-16 shadow-sm max-w-6xl mx-auto" id="printable-report">
      <div className="text-center border-b-8 border-primary/5 pb-12 mb-12"><h2 className="text-5xl font-black text-primary uppercase italic tracking-tighter">Senyuminn Kost</h2></div>
      <table className="w-full text-left border-collapse">
        <thead><tr className="bg-gray-50 text-[10px] font-black uppercase text-gray-400 border-b tracking-widest"><th className="p-6">Tgl Lapor</th><th className="p-6">Unit</th><th className="p-6">Masalah</th><th className="p-6">Teknisi</th><th className="p-6 text-right">Status</th></tr></thead>
        <tbody className="divide-y divide-gray-50">{complaints.map(c => (<tr key={c.id} className="text-[11px] text-gray-600 font-bold uppercase tracking-tight"><td className="p-6">{c.date}</td><td className="p-6 font-black">Kamar {c.roomId}</td><td className="p-6 italic">"{c.description}"</td><td className="p-6">{c.technician || '-'}</td><td className={`p-6 text-right font-black ${c.status === WorkflowStatus.FINISHED ? 'text-emerald-500' : 'text-rose-500'}`}>{c.status}</td></tr>))}</tbody>
      </table>
    </div>
  </div>
);

// --- 5. MAIN APP ---
const App = () => {
  const [view, setView] = useState<ViewType>('dashboard');
  const [rooms, setRooms] = useState<Room[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_ROOMS) || JSON.stringify(INITIAL_ROOMS)));
  const [complaints, setComplaints] = useState<Complaint[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_COMPLAINTS) || '[]'));
  const [selected, setSelected] = useState<Complaint | null>(null);

  useEffect(() => { localStorage.setItem(STORAGE_KEY_ROOMS, JSON.stringify(rooms)); }, [rooms]);
  useEffect(() => { localStorage.setItem(STORAGE_KEY_COMPLAINTS, JSON.stringify(complaints)); }, [complaints]);

  const handleAdd = (c: Complaint) => {
    setComplaints([c, ...complaints]);
    setRooms(rooms.map(r => r.id == c.roomId ? { ...r, status: RoomStatus.COMPLAINT, lastIssue: c.description } : r));
    setView('dashboard');
  };

  const handleUpdate = (id: string, st: WorkflowStatus, details: any) => {
    const updated = complaints.map(c => c.id === id ? { ...c, ...details, status: st, finishedDate: st === WorkflowStatus.FINISHED ? new Date().toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' }) : undefined } : c);
    setComplaints(updated);
    const comp = updated.find(c => c.id === id);
    if (comp) {
      if (st === WorkflowStatus.FINISHED) setRooms(rooms.map(r => r.id == comp.roomId ? { ...r, status: RoomStatus.NORMAL, lastIssue: undefined } : r));
      else if (st === WorkflowStatus.PROCESS) setRooms(rooms.map(r => r.id == comp.roomId ? { ...r, status: RoomStatus.REPAIR } : r));
    }
  };

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar currentView={view} setView={setView} onReset={() => { if(confirm('Hapus data?')) { localStorage.clear(); window.location.reload(); } }} />
      <main className="flex-1 ml-72 flex flex-col h-full bg-background dark:bg-gray-900 transition-colors overflow-hidden">
        <Header title={view.toUpperCase()} />
        <div className="flex-1 overflow-y-auto no-scrollbar pb-20">
          {view === 'dashboard' && <DashboardView rooms={rooms} complaints={complaints} />}
          {view === 'input' && <InputView onSave={handleAdd} />}
          {view === 'actions' && <ActionView complaints={complaints} onUpdate={handleUpdate} onPreview={setSelected} />}
          {view === 'report' && <ReportView complaints={complaints} />}
          {view === 'history' && (
            <div className="p-10 space-y-8 animate-in">
              <h2 className="text-2xl font-black dark:text-white uppercase tracking-tight">Arsip Selesai</h2>
              <div className="grid grid-cols-2 gap-4">
                {complaints.filter(c => c.status === WorkflowStatus.FINISHED).map(c => (
                  <div key={c.id} className="p-8 bg-white dark:bg-gray-800 rounded-[2.5rem] border border-gray-100 dark:border-gray-700 flex justify-between items-center shadow-sm">
                    <div><p className="font-black dark:text-white uppercase text-sm">Kamar {c.roomId} • {c.finishedDate}</p></div>
                    <button onClick={()=>setSelected(c)} className="px-6 py-3 bg-emerald-50 text-emerald-600 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-sm">Review</button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>
      {selected && <ReportPreview complaint={selected} onClose={() => setSelected(null)} />}
    </div>
  );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);
